-- Schema for Domain: product | Business: Agriculture | Version: v1_mvm
-- Generated on: 2026-05-01 18:45:53

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `agriculture_ecm`.`product` COMMENT 'SSOT for the agricultural product and commodity catalog — defining all sellable and transferable items including crop commodities (grains, produce, fiber), livestock products (meat, dairy, eggs), processed goods, seed/input products, and value-added products. Manages SKU/PLU/UPC codes, GMO status, organic certification flags (NOP), grading standards, MRL thresholds, product hierarchy classifications, COA and labeling (COOL) requirements aligned with USDA commodity codes. Supports organic, non-GMO, and conventional product lines.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `agriculture_ecm`.`product`.`agrochemical_product` (
    `agrochemical_product_id` BIGINT COMMENT 'Unique surrogate identifier for each agrochemical product record in the master catalog. Primary key for the agrochemical_product data product. Entity role: MASTER_RESOURCE.',
    `master_id` BIGINT COMMENT 'Foreign key linking to product.product_master. Business justification: agrochemical_product is a specialized subtype of the product master catalog. Every registered agrochemical (pesticide, herbicide, fungicide) must have a corresponding master product record for SKU/UPC',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: agrochemical_product.mrl_threshold_ppm is a denormalized copy of the authoritative MRL value stored in mrl_threshold. Adding mrl_threshold_id FK normalizes this reference, ensuring MRL values are main',
    `active_ingredient_concentration` DECIMAL(18,2) COMMENT 'The concentration of the active ingredient (AI) expressed as a percentage by weight (% w/w) or grams per liter (g/L) as stated on the EPA-registered label. Used to calculate application rates and verify MRL compliance.',
    `active_ingredient_name` STRING COMMENT 'The common chemical name of the primary active ingredient (AI) in the agrochemical product as defined by the EPA and IUPAC nomenclature (e.g., glyphosate, azoxystrobin, chlorpyrifos). Critical for MRL compliance, PHI determination, and resistance management programs.',
    `application_method` STRING COMMENT 'The EPA-label approved method(s) for applying the agrochemical product to crops or soil (e.g., foliar spray, soil incorporation, seed treatment, aerial application). Determines equipment requirements and VRA prescription compatibility. [ENUM-REF-CANDIDATE: foliar_spray|soil_incorporation|seed_treatment|aerial_application|drip_irrigation|broadcast|banding|fumigation|chemigation — promote to reference product]',
    `application_rate_unit` STRING COMMENT 'Unit of measure for the maximum application rate (e.g., oz/acre, lb/acre, L/ha). Required to correctly interpret and enforce the max_application_rate field for VRA prescriptions and compliance audits. [ENUM-REF-CANDIDATE: oz/acre|fl_oz/acre|lb/acre|pt/acre|qt/acre|gal/acre|kg/ha|L/ha — 8 candidates stripped; promote to reference product]',
    `concentration_unit` STRING COMMENT 'Unit of measure for the active ingredient concentration value (e.g., percent by weight, grams per liter). Ensures correct interpretation of the concentration field for application rate calculations.. Valid values are `percent_w/w|g/L|lb/gal|oz/gal|ppm`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when the agrochemical product record was first created in the master catalog system. Supports data lineage, audit trail requirements, and SOX financial reporting controls. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `epa_registration_number` STRING COMMENT 'The United States Environmental Protection Agency (EPA) registration number assigned to the pesticide product under FIFRA. Format: registrant-number-product-number (e.g., 524-308). Mandatory for all pesticide products sold or distributed in the US. Required for FSMA and GLOBALG.A.P. compliance documentation.. Valid values are `^[0-9]{1,6}-[0-9]{1,6}(-[0-9]{1,6})?$`',
    `epa_toxicity_category` STRING COMMENT 'The EPA acute toxicity category (I through IV) assigned to the agrochemical product based on oral, dermal, inhalation, and eye/skin irritation studies. Category I = most toxic (DANGER label); Category IV = least toxic. Drives PPE requirements, worker safety training, and medical surveillance programs.. Valid values are `I|II|III|IV`',
    `formulation_type` STRING COMMENT 'The physical and chemical formulation classification of the agrochemical product (e.g., emulsifiable concentrate, wettable powder, suspension concentrate, granule). Determines mixing, handling, and application equipment requirements. [ENUM-REF-CANDIDATE: emulsifiable_concentrate|wettable_powder|suspension_concentrate|granule|soluble_liquid|dry_flowable|water_dispersible_granule|microencapsulated|ultra_low_volume — promote to reference product]',
    `groundwater_advisory_flag` BOOLEAN COMMENT 'Indicates whether the EPA-registered label includes a groundwater advisory statement, signaling potential for leaching into groundwater under certain soil and climatic conditions. True = groundwater advisory present; False = no advisory. Drives BMP (Best Management Practices) and buffer zone requirements.',
    `hazmat_class` STRING COMMENT 'The US DOT hazardous materials classification for the agrochemical product as defined in 49 CFR. Determines transportation, labeling, placarding, and emergency response requirements. Used in TMS (Transportation Management System) for shipment compliance. [ENUM-REF-CANDIDATE: Class_1|Class_2|Class_3|Class_4|Class_5|Class_6|Class_8|Class_9|Not_Regulated — 9 candidates stripped; promote to reference product]',
    `label_approval_date` DATE COMMENT 'The date on which the current version of the EPA-registered product label was approved. The label is the law under FIFRA — this date establishes the authoritative version for compliance purposes and triggers label update workflows when amendments are approved.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when the agrochemical product record was most recently modified in the master catalog. Used for change tracking, data synchronization with source systems (SAP S/4HANA), and regulatory audit trails. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `manufacturer_name` STRING COMMENT 'The name of the company that physically manufactures or formulates the agrochemical product. May differ from the EPA registrant for generic or private-label products. Used for supplier management and procurement in SAP S/4HANA MM.',
    `max_application_rate` DECIMAL(18,2) COMMENT 'The maximum allowable application rate of the agrochemical product per application event as specified on the EPA-registered label. Used in conjunction with application_rate_unit to enforce label compliance and prevent over-application.',
    `max_seasonal_applications` STRING COMMENT 'The maximum number of times the agrochemical product may be applied per growing season per crop as specified on the EPA-registered label. Enforces resistance management and prevents MRL exceedances from cumulative applications.',
    `mode_of_action_code` STRING COMMENT 'The IRAC (Insecticide Resistance Action Committee), HRAC (Herbicide Resistance Action Committee), or FRAC (Fungicide Resistance Action Committee) mode of action classification code for the active ingredient. Critical for IPM resistance management rotation planning (e.g., HRAC Group 9 for glyphosate, FRAC Group 11 for strobilurins).. Valid values are `^[A-Z0-9]{1,5}$`',
    `omri_listed_flag` BOOLEAN COMMENT 'Indicates whether the agrochemical product appears on the Organic Materials Review Institute (OMRI) Products List, confirming suitability for use in certified organic operations. True = OMRI listed; False = not listed. Complements organic_approved_flag with third-party verification.',
    `organic_approved_flag` BOOLEAN COMMENT 'Indicates whether the agrochemical product is approved for use in certified organic production systems under the USDA National Organic Program (NOP). True = approved for organic use; False = not approved. Drives product selection for organic-certified fields and NOP compliance documentation.',
    `package_size` DECIMAL(18,2) COMMENT 'The quantity of agrochemical product contained in the standard commercial packaging unit (e.g., 2.5, 1.0, 5.0). Used in conjunction with package_unit for procurement, inventory management, and application rate calculations in SAP S/4HANA MM.',
    `package_unit` STRING COMMENT 'Unit of measure for the package size (e.g., gallon, liter, kg, lb). Combined with package_size to define the standard commercial unit for procurement, inventory, and cost tracking. [ENUM-REF-CANDIDATE: gallon|quart|pint|liter|kg|lb|oz|fl_oz|ton — 9 candidates stripped; promote to reference product]',
    `pre_harvest_interval_days` STRING COMMENT 'The minimum number of days that must elapse between the last application of the agrochemical product and the harvest of the treated crop, as specified on the EPA-registered label. Critical for MRL compliance and food safety under FSMA and GLOBALG.A.P. requirements.',
    `product_code` STRING COMMENT 'Internal SKU or material number assigned in SAP S/4HANA MM to uniquely identify the agrochemical product within the enterprise ERP system. Used for procurement, inventory, and cost tracking.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `product_name` STRING COMMENT 'The registered commercial or trade name of the agrochemical product as it appears on the EPA-registered label and product packaging (e.g., Roundup PowerMAX, Headline AMP Fungicide).',
    `product_status` STRING COMMENT 'Current lifecycle status of the agrochemical product in the master catalog. active = currently registered and available for use; discontinued = no longer manufactured or sold; suspended = EPA registration suspended pending review; pending_registration = awaiting EPA approval; cancelled = EPA registration voluntarily cancelled.. Valid values are `active|discontinued|suspended|pending_registration|cancelled`',
    `product_type` STRING COMMENT 'Classification of the agrochemical product by its primary mode of action or functional category. Drives regulatory compliance requirements, application protocols, and PHI/REI enforcement. [ENUM-REF-CANDIDATE: pesticide|herbicide|fungicide|insecticide|fertilizer|adjuvant|plant_growth_regulator|rodenticide|nematicide|fumigant — promote to reference product]',
    `registrant_name` STRING COMMENT 'The name of the company or individual holding the EPA registration for the agrochemical product (e.g., Bayer CropScience, Syngenta AG, BASF Corporation). Used for regulatory correspondence, label verification, and supplier qualification.',
    `registration_expiry_date` DATE COMMENT 'The date on which the EPA registration for the agrochemical product expires and must be renewed. Used to trigger re-registration workflows and prevent use of products with lapsed registrations. Critical for FSMA and GLOBALG.A.P. compliance audits.',
    `resistance_group` STRING COMMENT 'The resistance management group designation (e.g., HRAC Group 9, IRAC Group 4A, FRAC Group 3) used to plan chemical rotation programs and prevent development of resistant pest populations. Supports IPM compliance and GLOBALG.A.P. requirements.',
    `restricted_entry_interval_hours` STRING COMMENT 'The minimum number of hours that must pass after a pesticide application before workers may re-enter the treated area without personal protective equipment (PPE), as mandated by the EPA Worker Protection Standard (WPS). Required for OSHA and EPA compliance.',
    `restricted_use_flag` BOOLEAN COMMENT 'Indicates whether the agrochemical product is classified as a Restricted Use Pesticide (RUP) by the EPA, requiring purchase and application only by certified pesticide applicators. True = restricted use; False = general use. Drives applicator certification verification workflows.',
    `sds_document_reference` STRING COMMENT 'Reference identifier or URL to the current Safety Data Sheet (SDS) for the agrochemical product, compliant with OSHA Hazard Communication Standard (HazCom 2012) and GHS format. Required for worker safety, emergency response, and regulatory compliance. Sourced from SAP S/4HANA QM document management.',
    `shelf_life_months` STRING COMMENT 'The guaranteed shelf life of the agrochemical product in months from the date of manufacture, as specified by the manufacturer. Used for inventory rotation (FIFO), expiry date tracking, and procurement planning in SAP S/4HANA MM and Manhattan Associates WMS.',
    `signal_word` STRING COMMENT 'The EPA-mandated signal word appearing on the pesticide label indicating the acute toxicity category of the product: DANGER (Category I - most toxic), WARNING (Category II), CAUTION (Category III - least toxic), or EXEMPT. Drives PPE requirements and worker safety protocols.. Valid values are `DANGER|WARNING|CAUTION|EXEMPT`',
    `storage_temperature_max_c` DECIMAL(18,2) COMMENT 'The maximum storage temperature in degrees Celsius permitted for safe storage of the agrochemical product, as specified in the SDS and product label. Exceeding this threshold may cause product degradation, pressure buildup, or hazardous reactions. Used for WMS storage compliance.',
    `storage_temperature_min_c` DECIMAL(18,2) COMMENT 'The minimum storage temperature in degrees Celsius required to maintain product integrity and prevent degradation, as specified in the SDS and product label. Used for warehouse storage condition compliance in Manhattan Associates WMS.',
    `un_number` STRING COMMENT 'The United Nations (UN) four-digit identification number assigned to hazardous materials for international transport (e.g., UN1993 for flammable liquids, UN2902 for pesticides). Required on shipping documents, BOL, and placards for DOT and IATA compliance.. Valid values are `^UN[0-9]{4}$`',
    CONSTRAINT pk_agrochemical_product PRIMARY KEY(`agrochemical_product_id`)
) COMMENT 'Master catalog of all registered agrochemical products (pesticides, herbicides, fungicides, insecticides, fertilizers) used in crop protection and nutrition programs. Captures EPA registration number, active ingredient (AI), formulation type, MRL limits by crop, PHI, REI, SDS reference, restricted use status, and approved application methods. Serves as the SSOT for agrochemical compliance data supporting FSMA, EPA, and GLOBALG.A.P. requirements.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`product`.`commodity` (
    `commodity_id` BIGINT COMMENT 'Unique system-generated identifier for each agricultural commodity record in the enterprise catalog. Serves as the primary key for the commodity reference table. Role: MASTER_RESOURCE.',
    `mrl_threshold_id` BIGINT COMMENT 'Reference to the applicable Maximum Residue Limit (MRL) threshold record for this commodity. MRL defines the maximum concentration of pesticide residues legally permitted in or on food and feed commodities per EPA and Codex Alimentarius standards.',
    `allergen_flag` BOOLEAN COMMENT 'Indicates whether this commodity is classified as a major food allergen under FDA regulations (e.g., wheat, soybeans, peanuts, tree nuts, milk, eggs, fish, shellfish, sesame). Triggers allergen labeling and cross-contact prevention requirements.',
    `allergen_type` STRING COMMENT 'Specific allergen classification when allergen_flag is True (e.g., gluten/wheat, soy, peanut, tree nut, milk, egg, fish, shellfish, sesame). Required for FDA-compliant allergen labeling and HACCP allergen control plans.',
    `alternate_uom` STRING COMMENT 'Secondary unit of measure used for conversion, international trade, or customer-specific reporting (e.g., MT as alternate to BU for export contracts). Supports dual-unit inventory management in SAP MM. [ENUM-REF-CANDIDATE: BU|CWT|MT|LB|KG|TON|BBL|GAL|DOZ|HEAD|OTHER — 11 candidates stripped; promote to reference product]',
    `benchmark_price` DECIMAL(18,2) COMMENT 'Reference benchmark price per standard unit of measure for this commodity, typically derived from the nearest futures contract or USDA AMS market report. Used for budget planning, contract pricing, and financial reporting. Expressed in USD.',
    `commodity_class` STRING COMMENT 'High-level classification of the commodity by agricultural category. Drives domain-specific processing rules, storage requirements, and regulatory compliance workflows. [ENUM-REF-CANDIDATE: grain|oilseed|fiber|produce|livestock|dairy|poultry|aquaculture|other — promote to reference product]',
    `commodity_code` STRING COMMENT 'Externally-known enterprise code uniquely identifying the commodity across operational systems (SAP MM material number, Granular Farm Management commodity code). Used for cross-system reconciliation and procurement referencing.. Valid values are `^[A-Z0-9]{3,20}$`',
    `commodity_name` STRING COMMENT 'Human-readable name of the agricultural commodity (e.g., Yellow Corn No. 2, Hard Red Winter Wheat, Soybeans). Used in reporting, labeling, and trade documentation.',
    `commodity_status` STRING COMMENT 'Current lifecycle status of the commodity record in the enterprise catalog. Active = currently traded/produced; Inactive = temporarily suspended; Discontinued = no longer produced or traded; Pending Approval = awaiting regulatory or internal approval for new commodity onboarding.. Valid values are `active|inactive|discontinued|pending_approval`',
    `commodity_type` STRING COMMENT 'Sub-classification within the commodity class providing finer granularity (e.g., cereal grain, legume, root vegetable, red meat, whole milk). Supports product hierarchy analytics and USDA reporting segmentation.',
    `cool_required_flag` BOOLEAN COMMENT 'Indicates whether Country of Origin Labeling (COOL) is mandatory for this commodity under USDA AMS regulations. True = COOL labeling required at retail (e.g., beef, pork, lamb, chicken, fish, fresh/frozen produce); False = exempt.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this commodity record was first created in the enterprise data catalog. Supports data lineage, audit trail, and SOX financial reporting controls for master data governance.',
    `crop_year` STRING COMMENT 'The marketing crop year associated with this commodity definition (e.g., 2024 for the 2024/25 marketing year). Used for WASDE alignment, USDA program eligibility, and seasonal price benchmarking. Follows USDA marketing year conventions by commodity.',
    `effective_date` DATE COMMENT 'Date from which this commodity record is valid and active in the enterprise catalog. Used for temporal data management, crop year transitions, and regulatory compliance period tracking.',
    `exchange_market` STRING COMMENT 'Primary futures exchange where this commodity is traded (e.g., CBOT for grains, ICE for cotton and sugar). Determines which price feed and contract specifications apply for hedging and mark-to-market valuation. [ENUM-REF-CANDIDATE: CBOT|CME|ICE|NYMEX|KCBT|MGE|EURONEXT|OTHER — 8 candidates stripped; promote to reference product]',
    `exchange_ticker` STRING COMMENT 'Exchange ticker symbol for the commodity on futures markets (e.g., ZC for CBOT Corn, ZS for CBOT Soybeans, ZW for CBOT Wheat, CT for ICE Cotton). Used for market price benchmarking, hedging, and DTN/WASDE price feed integration.. Valid values are `^[A-Z]{1,6}$`',
    `expiry_date` DATE COMMENT 'Date on which this commodity record expires or is superseded in the enterprise catalog. Null indicates an open-ended active record. Used for catalog version management and regulatory compliance period end dates.',
    `fsma_covered_flag` BOOLEAN COMMENT 'Indicates whether this commodity is subject to FDA Food Safety Modernization Act (FSMA) requirements, including the Produce Safety Rule (21 CFR Part 112) or Preventive Controls for Human Food rule. Drives food safety plan and traceability requirements.',
    `gmo_status` STRING COMMENT 'Indicates whether the commodity is derived from genetically modified organisms (GMO), is non-GMO, or holds a certified GMO-free designation. Critical for labeling compliance (USDA National Bioengineered Food Disclosure Standard), export market access, and customer segregation requirements.. Valid values are `gmo|non_gmo|gmo_free_certified|not_applicable`',
    `haccp_category` STRING COMMENT 'HACCP food safety category classification for this commodity. Determines the applicable HACCP plan type and critical control point requirements for processing and handling. Aligns with GFSI, SQF, and BRC food safety management standards.. Valid values are `raw_agricultural|ready_to_eat|processed|not_applicable`',
    `hs_tariff_code` STRING COMMENT 'Harmonized System (HS) tariff classification code used for international trade documentation, customs declarations, import/export compliance, and duty rate determination. Typically 6–10 digits per WCO standard.. Valid values are `^[0-9]{6,10}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this commodity record. Used for change data capture (CDC) in the Databricks Silver Layer pipeline, audit trail maintenance, and master data synchronization across SAP S/4HANA, Granular, and Climate FieldView.',
    `moisture_content_max_pct` DECIMAL(18,2) COMMENT 'Maximum allowable moisture content percentage for this commodity at point of acceptance or storage. Exceeding this threshold triggers drying requirements or grade dockage. Critical for grain quality management per USDA GIPSA grading standards (e.g., corn ≤15.5%, soybeans ≤13%).',
    `ndvi_baseline` DECIMAL(18,2) COMMENT 'Reference Normalized Difference Vegetation Index (NDVI) baseline value for this commodity crop type at optimal growth stage, used for remote sensing yield estimation and crop health benchmarking in Climate FieldView and Esri ArcGIS analytics.',
    `nop_category` STRING COMMENT 'USDA National Organic Program (NOP) classification for this commodity. Certified organic = fully compliant with 7 CFR Part 205; Transitional = in 3-year transition period; Conventional = standard production; Not applicable = non-crop commodity.. Valid values are `certified_organic|transitional|conventional|not_applicable`',
    `organic_eligible_flag` BOOLEAN COMMENT 'Indicates whether this commodity is eligible for organic certification under the USDA National Organic Program (NOP). True = eligible for organic production and labeling; False = not eligible (e.g., synthetic inputs required). Drives segregation requirements in storage and logistics.',
    `origin_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code indicating the primary country of origin for this commodity (e.g., USA, BRA, ARG). Required for COOL compliance, import/export documentation, and country-of-origin risk assessment.. Valid values are `^[A-Z]{3}$`',
    `perishable_flag` BOOLEAN COMMENT 'Indicates whether the commodity is perishable and requires temperature-controlled storage or expedited handling. True = perishable (e.g., fresh produce, dairy, eggs); False = non-perishable (e.g., dry grains, cotton). Drives warehouse task prioritization in Manhattan Associates WMS.',
    `price_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the benchmark_price (e.g., USD, EUR, BRL). Supports multi-currency operations for international commodity trading and export contracts.. Valid values are `^[A-Z]{3}$`',
    `standard_uom` STRING COMMENT 'Primary unit of measure used for trading, pricing, and inventory tracking of this commodity (e.g., BU = Bushel for grains, CWT = Hundredweight for livestock, MT = Metric Ton for export). Aligns with SAP MM base unit of measure and USDA reporting standards. [ENUM-REF-CANDIDATE: BU|CWT|MT|LB|KG|TON|BBL|GAL|DOZ|HEAD|OTHER — 11 candidates stripped; promote to reference product]',
    `storage_temp_max_c` DECIMAL(18,2) COMMENT 'Maximum allowable storage temperature in degrees Celsius for this commodity. Exceeding this threshold triggers quality alerts and may result in grade downgrade or rejection per USDA grading standards.',
    `storage_temp_min_c` DECIMAL(18,2) COMMENT 'Minimum allowable storage temperature in degrees Celsius for this commodity to maintain quality and safety. Used to configure cold chain requirements in warehouse management and transportation planning.',
    `test_weight_min_lbs_bu` DECIMAL(18,2) COMMENT 'Minimum acceptable test weight in pounds per bushel for grade determination of this grain commodity (e.g., US No. 2 Yellow Corn = 54 lbs/bu). Used in USDA GIPSA official grading and price dockage calculations.',
    `typical_yield_per_acre` DECIMAL(18,2) COMMENT 'Reference average yield per acre for this commodity under standard production conditions, expressed in the standard_uom (e.g., 180 BU/acre for corn, 50 BU/acre for soybeans). Used as baseline for yield variance analysis, crop insurance, and USDA APH (Actual Production History) calculations.',
    `uom_conversion_factor` DECIMAL(18,2) COMMENT 'Numeric factor to convert from standard_uom to alternate_uom (e.g., 1 BU corn = 0.0254 MT; factor = 0.0254). Essential for export documentation, international invoicing, and cross-system inventory reconciliation.',
    `usda_commodity_code` STRING COMMENT 'Official USDA commodity code assigned by the Agricultural Marketing Service (AMS) or Farm Service Agency (FSA). Required for USDA program participation, federal reporting, and commodity loan eligibility determination.. Valid values are `^[0-9]{4,8}$`',
    `usda_grade_standard` STRING COMMENT 'Reference to the applicable USDA grade standard designation for this commodity (e.g., US No. 1, US No. 2, US Extra Fancy, USDA Choice). Determines quality thresholds, price premiums/discounts, and market eligibility. Linked to grading_standard reference product.',
    CONSTRAINT pk_commodity PRIMARY KEY(`commodity_id`)
) COMMENT 'Reference catalog of all agricultural commodities traded and produced by the enterprise — the raw, unprocessed agricultural outputs before they become sellable products. Includes grains (corn, wheat, soybeans, rice, barley), oilseeds (canola, sunflower), fiber crops (cotton), produce categories, and livestock commodity classes. Captures USDA commodity codes, HS (Harmonized System) tariff codes for international trade classification, commodity class, unit of measure (BU, CWT, MT), GMO status flag, organic eligibility, and commodity exchange ticker symbols (CBOT, CME). Linked to grading_standard and mrl_threshold for quality and compliance reference. Distinct from product_master: commodity defines WHAT is grown/raised; product_master defines HOW it is packaged and sold.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`product`.`master` (
    `master_id` BIGINT COMMENT 'Primary key for master',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: product_master represents sellable agricultural products that are often based on specific commodities (e.g., a corn product references the corn commodity). Adding commodity_id FK links the product to ',
    `grading_standard_id` BIGINT COMMENT 'FK to product.grading_standard',
    `hierarchy_id` BIGINT COMMENT 'Foreign key linking to product.product_hierarchy. Business justification: product_master is the central product catalog and must reference product_hierarchy for multi-level classification (division → category → subcategory → product line). This FK enables hierarchical repor',
    `brand_name` STRING COMMENT 'Commercial brand or trade name under which the product is marketed and sold. Relevant for value-added, processed, and seed products. Used in Salesforce CRM for customer-facing product catalog and sales pipeline management.',
    `coa_required_flag` BOOLEAN COMMENT 'Indicates whether a Certificate of Analysis (COA) must accompany each shipment of this product. True = COA required for quality verification, regulatory compliance, or customer contract requirements. Drives quality management workflows in SAP QM module.',
    `cool_country_of_origin` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code indicating the country of origin for Country of Origin Labeling (COOL) compliance. Mandatory for covered commodities under USDA COOL regulations (7 CFR Part 60 and 65). Used on retail labels and customer documentation.. Valid values are `^[A-Z]{3}$`',
    `cost_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the standard cost value (e.g., USD, EUR, CAD). Ensures multi-currency financial reporting accuracy for international agricultural operations.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this product master record was first created in the system. Provides audit trail for data governance and compliance with SOX financial reporting controls. Aligned with SAP MM material creation timestamp.',
    `discontinuation_date` DATE COMMENT 'Date on which this product was or is scheduled to be discontinued and removed from active use in transactions. Null for active products. Used for lifecycle management, inventory liquidation planning, and customer notification workflows.',
    `effective_date` DATE COMMENT 'Date from which this product record becomes active and available for use in transactions (purchasing, sales, production). Corresponds to SAP MM material creation date and marks the start of the product lifecycle in the enterprise catalog.',
    `food_safety_cert` STRING COMMENT 'Primary food safety certification standard applicable to this product (e.g., SQF - Safe Quality Food, BRC - British Retail Consortium, IFS - International Featured Standards, GLOBALG.A.P., HACCP, ISO 22000). Drives audit requirements and customer qualification criteria.. Valid values are `SQF|BRC|IFS|GLOBALG.A.P.|HACCP|ISO22000|none`',
    `fsma_regulated_flag` BOOLEAN COMMENT 'Indicates whether this product is subject to FDA Food Safety Modernization Act (FSMA) regulations, including Preventive Controls for Human Food (21 CFR Part 117) or Produce Safety Rule (21 CFR Part 112). Drives food safety plan requirements and traceability obligations.',
    `gap_compliant_flag` BOOLEAN COMMENT 'Indicates whether this product is produced under verified Good Agricultural Practices (GAP) standards. True = GAP-certified production. Required for certain retail customer contracts and export market access. Aligned with USDA GAP/GHP audit program.',
    `gmo_status` STRING COMMENT 'Detailed GMO classification of the product per FDA Bioengineered Food Disclosure Standard. conventional_gmo = contains bioengineered ingredients; non_gmo_verified = third-party verified non-GMO; bioengineered = must carry USDA BE disclosure; not_applicable = non-food or non-crop product.. Valid values are `conventional_gmo|non_gmo_verified|bioengineered|not_applicable`',
    `gtin` STRING COMMENT '14-digit Global Trade Item Number (GTIN) used for global supply chain identification, EDI transactions, and international trade. Encompasses UPC, EAN, and ITF-14 formats under the GS1 standard.. Valid values are `^[0-9]{14}$`',
    `hazmat_class` STRING COMMENT 'DOT hazardous materials classification code for products that are regulated as dangerous goods during transport (e.g., certain agricultural chemicals, fumigants, compressed gases). Null for non-hazardous products. Required for BOL (Bill of Lading) and shipping documentation.',
    `humidity_sensitivity_flag` BOOLEAN COMMENT 'Indicates whether this product requires controlled humidity storage conditions. True = humidity-sensitive product requiring specific relative humidity (RH) range in storage. Drives warehouse zone assignment and storage condition monitoring.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this product master record. Used for change data capture (CDC), data lineage tracking, and audit compliance. Aligned with SAP MM last change timestamp.',
    `lifecycle_status` STRING COMMENT 'Current lifecycle state of the product in the enterprise catalog. Controls whether the product can be ordered, produced, or sold. Aligned with SAP MM material status (MMSTATUS) field. seasonal indicates availability limited to specific growing or harvest periods.. Valid values are `active|discontinued|seasonal|pending_approval|blocked|phase_out`',
    `light_sensitive_flag` BOOLEAN COMMENT 'Indicates whether this product requires protection from light exposure during storage and transport. True = light-sensitive product (e.g., certain produce, seed varieties, specialty crops). Drives packaging and storage specification requirements.',
    `mrl_threshold_ppm` DECIMAL(18,2) COMMENT 'Maximum Residue Limit (MRL) threshold in parts per million (PPM) for pesticide or chemical residues permitted on this product per EPA and Codex Alimentarius standards. Used in quality control, COA validation, and export compliance. Null for non-food products.',
    `net_weight_kg` DECIMAL(18,2) COMMENT 'Standard net weight of one sellable unit of this product in kilograms (KG). Used for freight calculations, inventory valuation, customs declarations, and compliance with USDA and FDA labeling requirements. For bulk commodities, represents the standard unit weight (e.g., per bushel, per CWT).',
    `non_gmo_flag` BOOLEAN COMMENT 'Indicates whether this product is verified as non-GMO (Genetically Modified Organism). True = non-GMO verified product. Relevant for labeling compliance, customer preference management, and Non-GMO Project verification programs.',
    `organic_cert_number` STRING COMMENT 'Official USDA National Organic Program (NOP) certification number issued by the accredited certifying agent. Required on organic product labels and COA (Certificate of Analysis) documentation. Null for non-organic products.',
    `organic_certified_flag` BOOLEAN COMMENT 'Indicates whether this product is certified organic under the USDA National Organic Program (NOP). True = NOP-certified organic product. Drives labeling requirements, premium pricing, and supply chain segregation from conventional products.',
    `packaging_type` STRING COMMENT 'Type of packaging used for this product at the sellable unit level (e.g., bulk, bag, box, crate, pallet, drum). Drives warehouse storage configuration, shipping requirements, and labeling compliance. Aligned with SAP MM packaging data and Manhattan Associates WMS container types. [ENUM-REF-CANDIDATE: bulk|bag|box|crate|pallet|drum|tote|carton|bottle|pouch — 10 candidates stripped; promote to reference product]',
    `plu_code` STRING COMMENT '4- or 5-digit Price Look-Up (PLU) code assigned to fresh produce and bulk agricultural commodities for retail checkout identification. Managed by the International Federation for Produce Standards (IFPS).. Valid values are `^[0-9]{4,5}$`',
    `product_category` STRING COMMENT 'Second-level product hierarchy classification (e.g., Grains & Oilseeds, Fresh Produce, Dairy, Poultry, Beef, Pork, Fiber Crops, Horticultural Products, Seeds, Fertilizers). Used for reporting, pricing, and supply chain segmentation. [ENUM-REF-CANDIDATE: grains_oilseeds|fresh_produce|dairy|poultry|beef|pork|fiber_crops|horticultural|seeds|fertilizers — promote to reference product]',
    `product_line` STRING COMMENT 'Named product line or portfolio grouping to which this product belongs (e.g., Organic Harvest Line, Premium Grain Series, Non-GMO Select). Supports marketing segmentation, pricing strategy, and customer account management.',
    `product_name` STRING COMMENT 'The full commercial or trade name of the agricultural product as it appears on labeling, sales orders, and customer-facing documents. Aligned with SAP MM material description field.',
    `product_subcategory` STRING COMMENT 'Third-level product hierarchy classification providing granular segmentation within a product category (e.g., within Grains: Corn, Wheat, Soybeans, Rice; within Fresh Produce: Leafy Greens, Root Vegetables, Citrus). Supports detailed analytics and procurement planning.',
    `product_type` STRING COMMENT 'High-level classification of the agricultural product type distinguishing between raw commodities (grains, produce, fiber), processed goods, seed/input products, livestock-derived items (meat, dairy, eggs), value-added products, and agricultural inputs (fertilizers, chemicals). Drives linkage to type-specific detail tables.. Valid values are `commodity|processed_good|seed_input|livestock_product|value_added|agricultural_input`',
    `shelf_life_days` STRING COMMENT 'Maximum shelf life of the product in days from the date of production or harvest under standard storage conditions. Used for inventory rotation (FEFO - First Expired First Out), expiry date calculation, and food safety compliance per FSMA requirements.',
    `sku` STRING COMMENT 'Internal Stock Keeping Unit (SKU) code uniquely identifying a specific product variant for inventory tracking, order management, and warehouse operations. Corresponds to SAP MM material number used in WMS and ERP transactions.',
    `standard_cost` DECIMAL(18,2) COMMENT 'Standard cost per base unit of measure used for inventory valuation, variance analysis, and COGS (Cost of Goods Sold) calculation. Set during annual cost roll-up in SAP CO module. Confidential as it reflects internal pricing strategy and margin structure.',
    `storage_temp_max_c` DECIMAL(18,2) COMMENT 'Maximum permitted storage temperature in degrees Celsius for maintaining product quality and safety. Exceeding this threshold triggers quarantine hold procedures in the WMS and quality management system.',
    `storage_temp_min_c` DECIMAL(18,2) COMMENT 'Minimum required storage temperature in degrees Celsius for maintaining product quality and safety. Used by Manhattan Associates WMS for cold chain storage zone assignment and temperature monitoring compliance.',
    `unit_of_measure` STRING COMMENT 'Base unit of measure (UOM) for this product used in inventory management, purchasing, and sales transactions. Aligned with SAP MM base unit of measure (MEINS). Common agricultural units include BU (Bushel), CWT (Hundredweight), MT (Metric Ton), KG (Kilogram), LB (Pound). [ENUM-REF-CANDIDATE: KG|LB|MT|BU|CWT|EA|CS|BAG|TON|L|GAL — 11 candidates stripped; promote to reference product]',
    `upc` STRING COMMENT '12-digit Universal Product Code (UPC) barcode identifier used for retail point-of-sale scanning, consumer packaging, and retail distribution. Required for products sold through retail channels.. Valid values are `^[0-9]{12}$`',
    `usda_commodity_code` STRING COMMENT 'Official USDA commodity classification code used for federal reporting, subsidy programs, crop insurance, and WASDE (World Agricultural Supply and Demand Estimates) alignment. Maps to USDA Agricultural Marketing Service commodity codes.',
    `valuation_class` STRING COMMENT 'SAP MM valuation class code that determines the G/L (General Ledger) account assignment for inventory postings. Controls how inventory value is recorded in financial accounting (FI module) and cost accounting (CO module). Critical for COGS (Cost of Goods Sold) and inventory valuation reporting.',
    CONSTRAINT pk_master PRIMARY KEY(`master_id`)
) COMMENT 'Central master catalog and SSOT for all sellable, transferable, and internally consumed agricultural products. Every product in the enterprise — whether a raw commodity packaged for sale, a processed good, a seed variety, a livestock-derived item, or an agricultural input — has exactly one product_master record. Captures SKU, PLU, UPC, GTIN codes, product hierarchy classification, brand, product line, net weight, packaging type, shelf life, storage requirements (temperature range, humidity, light sensitivity), and product lifecycle status (active, discontinued, seasonal). Distinguishes between conventional, organic (NOP-certified), and non-GMO product lines. Type-specific detail is held in linked detail tables (seed_variety, livestock_product, processed_good, input_product). Aligned with SAP S/4HANA Material Master (MM module).';

CREATE OR REPLACE TABLE `agriculture_ecm`.`product`.`hierarchy` (
    `hierarchy_id` BIGINT COMMENT 'Unique surrogate identifier for each node in the product hierarchy. Primary key for the product_hierarchy data product in the Databricks Silver Layer.',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: hierarchy stores grading_standard_code (STRING) as a denormalized reference to the applicable grading standard for a product classification level. The grading_standard table is the authoritative SSOT ',
    `parent_hierarchy_id` BIGINT COMMENT 'Self-referencing identifier pointing to the immediate parent node in the product hierarchy tree. Null for root-level Division nodes. Enables recursive traversal for roll-up reporting across crop commodities, livestock products, and processed goods.',
    `commodity_group` STRING COMMENT 'Broad commodity grouping for this hierarchy node aligned with USDA and market reporting conventions. Examples: Grains & Oilseeds, Fruits & Vegetables, Dairy, Poultry & Eggs, Meat & Livestock, Fiber Crops, Specialty Crops, Crop Inputs. Used in WASDE reporting and market price benchmarking. [ENUM-REF-CANDIDATE: Grains & Oilseeds|Fruits & Vegetables|Dairy|Poultry & Eggs|Meat & Livestock|Fiber Crops|Specialty Crops|Crop Inputs — promote to reference product]',
    `cool_required_flag` BOOLEAN COMMENT 'Indicates whether Country of Origin Labeling (COOL) is mandatory for products in this hierarchy node under USDA AMS regulations. True = COOL labeling required on all products in this node; False = COOL not required. Drives labeling compliance workflows and retail packaging requirements.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this product hierarchy node record was first created in the system. Supports data lineage, audit trail, and Silver Layer ingestion tracking. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `data_steward` STRING COMMENT 'Name or identifier of the business data steward responsible for maintaining the accuracy and completeness of this hierarchy node. Supports data governance accountability, change management workflows, and master data management (MDM) ownership tracking.',
    `division_code` STRING COMMENT 'SAP S/4HANA Sales Division code associated with this hierarchy node. Drives pricing, sales organization assignment, and profit center determination. Examples: CROP (Crop Commodities), LVST (Livestock Products), PROC (Processed Goods), SEED (Seed & Inputs), VADD (Value-Added Products).. Valid values are `^[A-Z0-9]{1,4}$`',
    `effective_from_date` DATE COMMENT 'Date from which this product hierarchy node is valid and active for product classification. Supports temporal hierarchy management and ensures historical accuracy when hierarchy structures change. Used in SAP S/4HANA time-dependent product hierarchy configurations.',
    `effective_to_date` DATE COMMENT 'Date after which this product hierarchy node is no longer valid for new product assignments. Null indicates an open-ended, currently active node. Supports hierarchy versioning and ensures products are not assigned to expired classification nodes.',
    `external_reference_code` STRING COMMENT 'Cross-reference code mapping this hierarchy node to an external classification system such as UNSPSC (United Nations Standard Products and Services Code), HS (Harmonized System) tariff code, or trading partner category code. Supports EDI, customs documentation, and global trade compliance.. Valid values are `^[A-Z0-9_-]{1,50}$`',
    `food_safety_category` STRING COMMENT 'FDA/USDA food safety classification for products in this hierarchy node. Determines applicable food safety regulations, inspection requirements, and labeling rules. Ready-to-Eat products require stricter controls than Raw Agricultural Commodities. Non-Food and Crop Input nodes are exempt from food safety rules.. Valid values are `Ready-to-Eat|Raw Agricultural Commodity|Processed Food|Animal Feed|Non-Food|Crop Input`',
    `fsma_category` STRING COMMENT 'FDA Food Safety Modernization Act (FSMA) regulatory category applicable to products in this hierarchy node. Determines which FSMA rules govern production, handling, and supply chain requirements. Drives compliance program assignment and audit scope.. Valid values are `Produce Safety Rule|Preventive Controls Human Food|Preventive Controls Animal Food|Foreign Supplier Verification|Not Applicable`',
    `gfsi_scheme_applicable` STRING COMMENT 'Primary Global Food Safety Initiative (GFSI)-recognized certification scheme applicable to products in this hierarchy node. Drives supplier qualification, audit requirements, and customer contract compliance. Values: SQF (Safe Quality Food), BRC (British Retail Consortium), IFS (International Featured Standards), GLOBALG.A.P., Not Applicable.. Valid values are `SQF|BRC|IFS|GLOBALG.A.P.|Not Applicable`',
    `gmo_classification` STRING COMMENT 'Indicates the Genetically Modified Organism (GMO) status applicable to products in this hierarchy node. Values: GMO (contains genetically modified material), Non-GMO (no GMO material, not certified), GMO-Free Certified (third-party verified non-GMO), Not Applicable (e.g., agrochemicals). Required for COOL labeling, USDA BE (Bioengineered) disclosure, and export documentation.. Valid values are `GMO|Non-GMO|GMO-Free Certified|Not Applicable`',
    `gpc_brick_code` STRING COMMENT 'GS1 Global Product Classification (GPC) Brick-level code for this hierarchy node. Enables standardized product categorization for retail trading partners, EDI transactions, and global supply chain interoperability. Particularly relevant for produce, dairy, and packaged goods nodes.. Valid values are `^[0-9]{8}$`',
    `haccp_applicable_flag` BOOLEAN COMMENT 'Indicates whether Hazard Analysis and Critical Control Points (HACCP) plans are required for products in this hierarchy node. True = HACCP plan mandatory (e.g., meat, poultry, juice, seafood); False = HACCP not required. Drives food safety program assignment and FSIS/FDA audit requirements.',
    `hazmat_flag` BOOLEAN COMMENT 'Indicates whether products in this hierarchy node are classified as hazardous materials requiring special handling, storage, and transportation documentation (e.g., certain agrochemicals, fertilizers). True = HAZMAT classification applies; False = standard handling. Drives SDS (Safety Data Sheet) requirements and DOT/EPA compliance.',
    `hierarchy_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this hierarchy node. Corresponds to the SAP S/4HANA PRODH (Product Hierarchy) field used in SD pricing and MM material classification. Used for cross-system integration with SAP, Oracle NetSuite, and Granular Farm Management.. Valid values are `^[A-Z0-9_-]{2,40}$`',
    `hierarchy_description` STRING COMMENT 'Detailed business description of this hierarchy node, including the scope of products it encompasses, applicable production methods, and any relevant regulatory or quality notes. Used in training materials, data catalogs, and business user documentation.',
    `hierarchy_level` STRING COMMENT 'Numeric depth of this node within the hierarchy tree. Level 1 = Division (e.g., Crop Commodities), Level 2 = Category (e.g., Grains), Level 3 = Sub-Category (e.g., Cereal Grains), Level 4 = Product Family (e.g., Corn), Level 5 = SKU/Item. Supports roll-up reporting in SAP S/4HANA SD and analytics.',
    `hierarchy_name` STRING COMMENT 'Human-readable name of this hierarchy node (e.g., Grains & Oilseeds, Fresh Produce, Dairy Products, Crop Inputs - Seed). Used in reporting, category management, and retail planogram structures.',
    `hierarchy_status` STRING COMMENT 'Current lifecycle status of this product hierarchy node. Active = in use for product classification and reporting; Inactive = temporarily disabled; Deprecated = replaced by a new node, retained for historical data; Pending Approval = awaiting business owner sign-off before activation. Controls whether new products can be assigned to this node.. Valid values are `Active|Inactive|Deprecated|Pending Approval`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this product hierarchy node record. Used for incremental data pipeline processing, change detection, and audit compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `level_name` STRING COMMENT 'Business label for the hierarchy depth at this node. Standardized level names: Division, Category, Sub-Category, Product Family, SKU. Enables consistent labeling in reports and dashboards without requiring numeric level interpretation.. Valid values are `Division|Category|Sub-Category|Product Family|SKU`',
    `mrl_applicable_flag` BOOLEAN COMMENT 'Indicates whether EPA/Codex Alimentarius Maximum Residue Limits (MRL) for pesticide residues apply to products in this hierarchy node. True = MRL testing and compliance required; False = MRL not applicable (e.g., non-food inputs). Drives residue testing protocols and COA requirements.',
    `organic_eligible_flag` BOOLEAN COMMENT 'Indicates whether products classified under this hierarchy node are eligible for USDA National Organic Program (NOP) organic certification. True = organic product line; False = conventional or non-organic. Drives organic certification tracking, NOP compliance workflows, and organic premium pricing.',
    `path` STRING COMMENT 'Materialized full path string from root to this node using delimiter notation (e.g., Crop Commodities / Grains / Cereal Grains / Corn). Supports efficient hierarchy traversal queries in Databricks without recursive CTEs. Maintained as a denormalized convenience field.',
    `phi_required_flag` BOOLEAN COMMENT 'Indicates whether Pre-Harvest Interval (PHI) tracking is required for products in this hierarchy node. True = PHI compliance mandatory (food/feed crops subject to pesticide application); False = PHI not applicable. Drives crop protection event tracking and harvest scheduling compliance.',
    `plu_category_code` STRING COMMENT 'International Federation for Produce Standards (IFPS) Price Look-Up (PLU) category code for fresh produce hierarchy nodes. Used at retail point-of-sale for produce identification and pricing. Applicable primarily to fresh fruit, vegetable, and herb product hierarchy nodes.. Valid values are `^[0-9]{4,5}$`',
    `pricing_uom` STRING COMMENT 'Unit of measure used for pricing and invoicing products in this hierarchy node. May differ from reporting UOM (e.g., corn priced per BU but reported in MT). Drives SAP S/4HANA SD condition record pricing and Oracle NetSuite invoice generation. [ENUM-REF-CANDIDATE: BU|CWT|MT|LB|KG|TON|DOZ|EA|GAL|L — 10 candidates stripped; promote to reference product]',
    `product_line_type` STRING COMMENT 'High-level classification of the product line represented by this hierarchy node. Distinguishes between Crop Commodity (grains, produce, fiber), Livestock Product (meat, dairy, eggs), Processed Good, Seed Input, Value-Added, and Agrochemical product lines. Drives business rules, compliance requirements, and reporting segmentation.. Valid values are `Crop Commodity|Livestock Product|Processed Good|Seed Input|Value-Added|Agrochemical`',
    `reporting_uom` STRING COMMENT 'Primary unit of measure used for volume and yield reporting for products in this hierarchy node. Aligned with USDA NASS and WASDE reporting conventions. BU = Bushel, CWT = Hundredweight, MT = Metric Ton, LB = Pound, KG = Kilogram, TON = Short Ton, DOZ = Dozen, EA = Each, GAL = Gallon, L = Liter. Used in SAP S/4HANA MM base unit of measure configuration. [ENUM-REF-CANDIDATE: BU|CWT|MT|LB|KG|TON|DOZ|EA|GAL|L — 10 candidates stripped; promote to reference product]',
    `retail_category_code` STRING COMMENT 'Internal retail category management code used for merchandising, planogram assignment, and retail buyer reporting. Aligns with PLU (Price Look-Up) category structures and retail trading partner category definitions. Used in Salesforce CRM for customer-facing category reporting.. Valid values are `^[A-Z0-9_-]{1,20}$`',
    `sap_material_group` STRING COMMENT 'SAP S/4HANA Material Group (MATKL field) associated with this hierarchy node. Used in SAP MM for procurement categorization, account determination, and purchasing info records. Enables cross-reference between the product hierarchy and SAP material master classification.. Valid values are `^[A-Z0-9]{4,9}$`',
    `sap_product_hierarchy` STRING COMMENT 'SAP S/4HANA native Product Hierarchy (PRODH) code for this node, up to 18 characters. Used directly in SAP SD condition records for pricing, rebate agreements, and sales reporting. Serves as the integration key between this data product and SAP S/4HANA SD/MM modules.. Valid values are `^[A-Z0-9]{1,18}$`',
    `sort_sequence` STRING COMMENT 'Numeric sort order for displaying this hierarchy node among its siblings at the same parent level. Controls the display sequence in SAP S/4HANA product hierarchy browsers, reporting dashboards, and retail category management tools. Lower numbers appear first.',
    `temperature_class` STRING COMMENT 'Required storage and handling temperature classification for products in this hierarchy node. Drives cold chain logistics requirements, warehouse slotting in Manhattan Associates WMS, and transportation mode selection in TMS. Values: Ambient, Refrigerated, Frozen, Controlled Atmosphere.. Valid values are `Ambient|Refrigerated|Frozen|Controlled Atmosphere`',
    `usda_commodity_code` STRING COMMENT 'Official USDA commodity classification code assigned to this hierarchy node. Aligns with USDA Agricultural Marketing Service (AMS) and National Agricultural Statistics Service (NASS) commodity groupings. Required for USDA regulatory reporting, WASDE alignment, and federal program compliance.. Valid values are `^[0-9]{4,8}$`',
    CONSTRAINT pk_hierarchy PRIMARY KEY(`hierarchy_id`)
) COMMENT 'Defines the multi-level classification hierarchy for all agricultural products — from enterprise product division down through category, sub-category, product family, and individual SKU. Supports USDA commodity groupings, internal merchandising hierarchies, and retail category management structures. Enables roll-up reporting across crop commodities, livestock products, processed goods, seed/input products, and value-added lines. Used in SAP S/4HANA SD and MM modules for pricing and reporting hierarchies.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`product`.`seed_variety` (
    `seed_variety_id` BIGINT COMMENT 'Unique system-generated identifier for each seed variety record in the master catalog. Primary key for the seed_variety data product.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: seed_variety represents cultivars of specific crop species (corn, soybean, wheat) that correspond directly to commodity types in the commodity catalog. Linking seed_variety to commodity via commodity_',
    `gmo_declaration_id` BIGINT COMMENT 'Foreign key linking to product.gmo_declaration. Business justification: seed_variety carries three denormalized GMO attributes: aphis_petition_number (the APHIS regulatory petition number for the GMO event), gmo_status (STRING), and non_gmo_verified_flag (BOOLEAN). The gm',
    `master_id` BIGINT COMMENT 'Foreign key linking to product.product_master. Business justification: seed_variety is a specialized product subtype representing cultivars sold as input products. It must reference product_master for unified SKU/UPC management, lifecycle status, and commercial catalog i',
    `breeder_name` STRING COMMENT 'Name of the seed company, research institution, or individual breeder that developed and holds intellectual property rights over this variety (e.g., Bayer Crop Science, Corteva Agriscience, Syngenta). Required for licensing compliance and royalty tracking.',
    `catalog_year` STRING COMMENT 'The crop year (4-digit year) for which this seed variety is listed in the commercial product catalog. Used for annual catalog management, variety retirement tracking, and historical performance analysis in Granular Farm Management and Climate FieldView.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this seed variety record was first created in the master catalog system. Used for data lineage, audit trail, and Silver Layer ingestion tracking in the Databricks Lakehouse.',
    `crop_species` STRING COMMENT 'Botanical species name of the crop (e.g., Zea mays for corn, Glycine max for soybean, Triticum aestivum for wheat). Aligns with USDA PLANTS Database taxonomy and supports regulatory reporting to APHIS and EPA.',
    `crop_type` STRING COMMENT 'High-level agronomic classification of the crop category. Used for product hierarchy segmentation, supply chain routing, and USDA commodity code alignment. [ENUM-REF-CANDIDATE: grain|oilseed|fiber|forage|vegetable|fruit|pulse|tuber|specialty|cover_crop — promote to reference product]',
    `days_to_maturity` STRING COMMENT 'Average number of calendar days from planting to physiological maturity under typical growing conditions for the primary production region. Used for crop scheduling, harvest planning, and frost risk assessment in Climate FieldView and Granular Farm Management.',
    `discontinuation_date` DATE COMMENT 'Date on which this seed variety was officially discontinued from commercial sale or production. Null if the variety is still active. Used for catalog management, inventory clearance planning, and historical crop planning records.',
    `disease_resistance_profile` STRING COMMENT 'Structured description of the varietys resistance or tolerance ratings to key crop diseases (e.g., Gray Leaf Spot: R, Northern Corn Leaf Blight: MR, Gosss Wilt: S). Ratings typically follow industry conventions: R=Resistant, MR=Moderately Resistant, MS=Moderately Susceptible, S=Susceptible. Informs crop protection planning and IPM programs.',
    `drought_tolerance_rating` STRING COMMENT 'Categorical rating of the varietys ability to maintain yield under water-deficit stress conditions. Used for irrigation planning, water resource management, and ET (Evapotranspiration)-based irrigation scheduling in precision agriculture systems.. Valid values are `excellent|good|fair|poor`',
    `germination_rate_pct` DECIMAL(18,2) COMMENT 'Minimum guaranteed germination rate percentage for this seed variety as tested under AOSA (Association of Official Seed Analysts) standard germination test conditions. Expressed as a percentage (e.g., 95.00 = 95%). Required for Federal Seed Act label compliance and quality assurance.',
    `herbicide_tolerance_traits` STRING COMMENT 'Comma-separated list of herbicide tolerance traits present in this variety (e.g., glyphosate, glufosinate, dicamba). Used for agrochemical selection, VRA prescription compatibility, and EPA resistance management compliance. Supports IPM resistance group tracking.',
    `insect_resistance_traits` STRING COMMENT 'Comma-separated list of insect resistance traits (e.g., Bt Cry1Ab, Cry3Bb1, VIP3A) present in this variety. Used for EPA insect resistance management (IRM) compliance, refuge planning, and IPM program design. Required for APHIS regulatory documentation on Bt crops.',
    `introduction_date` DATE COMMENT 'Date on which this seed variety was first commercially introduced to the market or added to the internal product catalog. Used for variety lifecycle management, performance trend analysis, and regulatory documentation.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this seed variety record in the master catalog. Used for change tracking, data freshness monitoring, and incremental ETL processing in the Databricks Lakehouse Silver Layer.',
    `licensor_code` STRING COMMENT 'Unique identifier for the seed licensor or technology provider as registered in the ERP procurement master. Used to link seed variety to licensing agreements, royalty schedules, and supplier records in SAP S/4HANA MM.. Valid values are `^[A-Z0-9-]{2,20}$`',
    `nop_organic_eligible` BOOLEAN COMMENT 'Indicates whether this seed variety is eligible for use in USDA National Organic Program (NOP) certified organic production. True = organically produced seed available and eligible; False = not eligible (e.g., treated with prohibited substances or GMO). Drives organic crop planning and NOP compliance documentation.',
    `package_weight_kg` DECIMAL(18,2) COMMENT 'Net weight of the standard commercial seed package in kilograms. Used for freight calculation, warehouse storage planning, and logistics management in Manhattan Associates WMS and TMS (Transportation Management System).',
    `plant_height_category` STRING COMMENT 'Categorical classification of the varietys typical plant height at maturity. Used for equipment calibration (combine header height), lodging risk assessment, and field operation planning in John Deere Operations Center.. Valid values are `short|medium|tall|very_tall`',
    `plant_variety_protection_number` STRING COMMENT 'USDA Plant Variety Protection Office certificate number assigned to this variety, granting intellectual property protection to the breeder. Null if the variety is not PVP-protected or is in the public domain. Required for licensing compliance and royalty management.',
    `purity_pct` DECIMAL(18,2) COMMENT 'Percentage of pure seed (by weight) of the labeled variety in the seed lot, as determined by official seed analysis. Required for Federal Seed Act label compliance. Expressed as a percentage (e.g., 99.50 = 99.5% pure seed).',
    `recommended_planting_regions` STRING COMMENT 'Comma-separated list of geographic regions, states, or USDA Plant Hardiness Zones where this variety is agronomically recommended for commercial production (e.g., Corn Belt, Northern Plains, Zone 5-7). Supports geographic segmentation in Esri ArcGIS field mapping and regional sales planning.',
    `relative_maturity_rating` DECIMAL(18,2) COMMENT 'Numeric relative maturity rating indicating the number of days or heat units required for the variety to reach physiological maturity relative to a standard check variety (e.g., 108.5 for a 108.5-day corn hybrid, 3.8 for a 3.8 maturity group soybean). Critical for crop planning, planting date optimization, and frost risk management in Climate FieldView and Trimble Ag Software.',
    `seed_class` STRING COMMENT 'Official seed certification class indicating the generation and purity level of the seed as defined by the Association of Official Seed Certifying Agencies (AOSCA). Classes: breeder (source seed from originating breeder), foundation (first generation from breeder seed), registered (second generation), certified (commercially distributed certified seed), commercial (uncertified commercial seed).. Valid values are `breeder|foundation|registered|certified|commercial`',
    `seed_size_category` STRING COMMENT 'Physical size classification of the seed kernel used for planter plate selection, seeding equipment calibration, and seed unit weight calculations. Affects planter population accuracy and is required for John Deere Operations Center equipment setup.. Valid values are `flat|round|large|medium|small`',
    `seed_treatment_active_ingredient` STRING COMMENT 'Comma-separated list of active ingredients (AI) in the seed treatment formulation (e.g., clothianidin, metalaxyl, fludioxonil). Required for MRL compliance, EPA registration cross-reference, and FSMA produce safety rule documentation.',
    `seed_treatment_applied` STRING COMMENT 'Name or code of the seed treatment product(s) applied to the seed lot prior to sale or planting (e.g., Poncho 1250 + Acceleron, Cruiser Maxx Vibrance). Includes fungicide, insecticide, and biological seed treatments. Required for EPA label compliance, PHI/REI tracking, and NOP organic eligibility determination.',
    `seeding_rate_per_acre` DECIMAL(18,2) COMMENT 'Manufacturer or agronomist-recommended seeding rate expressed as seeds per acre for optimal stand establishment. Used for VRA (Variable Rate Application) prescription generation in Trimble Ag Software and seed quantity planning in Granular Farm Management.',
    `seeds_per_unit` STRING COMMENT 'Number of seeds per standard commercial unit (e.g., seeds per 80,000-count bag for corn, seeds per 140,000-count bag for soybean). Used for inventory management, seeding rate calculations, and order quantity planning in SAP S/4HANA MM and Manhattan Associates WMS.',
    `trait_package` STRING COMMENT 'Descriptive label of the bundled biotechnology or conventionally bred trait stack applied to this variety (e.g., RoundupReady2Xtend + Bollgard3, Enlist E3, LibertyLink GT27). Captures herbicide tolerance, insect resistance, drought tolerance, and other engineered or selected traits. Used for IPM planning, agrochemical compatibility, and regulatory reporting.',
    `variety_code` STRING COMMENT 'Internally assigned alphanumeric code uniquely identifying the seed variety in ERP and FMIS systems (e.g., SAP S/4HANA material master number or Trimble Ag Software variety code). Used as the business key for cross-system integration and SKU linkage.. Valid values are `^[A-Z0-9-]{3,30}$`',
    `variety_name` STRING COMMENT 'Commercial or proprietary name of the seed variety as registered by the breeder or licensor (e.g., DeKalb DKC62-08, Pioneer P1197AM). This is the primary human-readable identifier used in field operations, procurement, and sales.',
    `variety_status` STRING COMMENT 'Current lifecycle status of the seed variety in the product catalog. active indicates commercially available; discontinued indicates no longer sold or planted; under_review indicates pending regulatory or internal evaluation; pending_approval indicates awaiting APHIS or NOP certification; withdrawn indicates removed due to regulatory or quality issues.. Valid values are `active|discontinued|under_review|pending_approval|withdrawn`',
    `yield_potential_rating` STRING COMMENT 'Categorical rating of the varietys yield potential relative to comparable varieties in the same crop class and maturity group, as determined by multi-environment trial (MET) data. Used for variety selection, agronomic planning, and YPM (Yield Per Acre Metric) benchmarking in Granular Farm Management.. Valid values are `exceptional|above_average|average|below_average`',
    CONSTRAINT pk_seed_variety PRIMARY KEY(`seed_variety_id`)
) COMMENT 'Master catalog of all seed varieties and cultivars used in crop production and sold as input products. Captures variety name, crop species, breeder/licensor, trait package (herbicide tolerance, insect resistance), GMO status, non-GMO verification status, relative maturity rating, yield potential rating, disease resistance profile, and seed treatment applied. Tracks NOP organic seed eligibility and APHIS biotech regulatory status. Sourced from Trimble Ag Software and Climate FieldView variety databases.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`product`.`organic_certification` (
    `organic_certification_id` BIGINT COMMENT 'Unique system-generated identifier for each organic certification record. Primary key for the organic_certification data product.',
    `master_id` BIGINT COMMENT 'Reference to the agricultural product or commodity in the product catalog that is covered under this organic certification. Links the certification record to the specific sellable or transferable item for organic labeling and premium pricing eligibility.',
    `allowed_materials_list_reference` STRING COMMENT 'Document reference or identifier for the approved materials list associated with this certification. Lists all inputs (fertilizers, pesticides, processing aids) approved for use under the certified organic system plan, cross-referenced against the USDA National List of Allowed and Prohibited Substances.',
    `annual_renewal_status` STRING COMMENT 'Tracks the current annual renewal status of the organic certification. Renewed: successfully renewed for the current certification year. Pending_renewal: renewal application submitted and under review. Not_renewed: operation chose not to renew. Overdue: renewal deadline passed without submission.. Valid values are `renewed|pending_renewal|not_renewed|overdue`',
    `certificate_document_reference` STRING COMMENT 'File path, document management system reference, or URL pointing to the scanned or digital copy of the official organic certificate issued by the certifying agent. Supports audit trail, labeling compliance verification, and customer COA (Certificate of Analysis) requests.',
    `certificate_number` STRING COMMENT 'Externally-issued certificate number assigned by the accredited certifying agent. This is the official document reference used in regulatory filings, labeling claims, and audit trails under USDA NOP requirements.',
    `certification_scope` STRING COMMENT 'The operational scope covered by this organic certificate as defined by USDA NOP. Valid values: crops (field and greenhouse crop production), livestock (animal husbandry), handling_processing (post-harvest handling and processing operations), wild_crops (wild-harvested plant materials), aquatic_animals (aquatic animal production). Determines which products and operations are covered under this certificate.. Valid values are `crops|livestock|handling_processing|wild_crops|aquatic_animals`',
    `certification_status` STRING COMMENT 'Current lifecycle status of the organic certification. Active: certificate is valid and in good standing. Suspended: temporarily halted pending investigation or corrective action. Revoked: permanently cancelled due to violation. Pending: application submitted, awaiting certifying agent approval. Expired: past expiration date without renewal. Withdrawn: voluntarily relinquished by the operation.. Valid values are `active|suspended|revoked|pending|expired|withdrawn`',
    `certified_acreage` DECIMAL(18,2) COMMENT 'Total land area in acres covered under this organic certification. Represents the certified organic production footprint and is used for yield planning, premium pricing calculations, and regulatory reporting to USDA.',
    `certifying_agent_code` STRING COMMENT 'The official USDA-assigned accreditation code or identifier for the certifying agent. Used for regulatory cross-referencing with USDA AMS accreditation records and electronic filing systems.',
    `certifying_agent_name` STRING COMMENT 'The name of the USDA-accredited certifying agent (ACA) that issued and administers this organic certificate. Certifying agents are third-party organizations accredited by the USDA Agricultural Marketing Service (AMS) to certify organic operations.',
    `cool_compliant_flag` BOOLEAN COMMENT 'Indicates whether the organic certification record supports Country of Origin Labeling (COOL) compliance requirements. COOL mandates disclosure of the country of origin for covered commodities at retail, and organic products must meet both NOP and COOL labeling requirements.',
    `country_of_origin` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code indicating the country where the certified organic product was produced or primarily grown. Required for COOL compliance and international organic equivalency agreements.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this organic certification record was first created in the system. Used for audit trail, data lineage tracking, and compliance record-keeping in the Databricks Silver Layer.',
    `effective_date` DATE COMMENT 'The date on which the organic certification becomes legally valid and binding. Marks the start of the certified period during which organic labeling claims and premium pricing are authorized.',
    `equivalency_standard` STRING COMMENT 'Identifies the specific international organic standard or equivalency arrangement recognized by this certification (e.g., EU Organic, Canada Organic, Japan JAS Organic, IFOAM). Populated only when international_equivalency_flag is True.',
    `expiration_date` DATE COMMENT 'The date on which the organic certification expires and must be renewed to maintain organic status. Organic certificates are typically issued on an annual basis. Expiration triggers renewal workflow and may affect organic premium pricing eligibility.',
    `fsma_compliant_flag` BOOLEAN COMMENT 'Indicates whether the certified organic operation is also compliant with applicable Food Safety Modernization Act (FSMA) rules, including the Produce Safety Rule and Preventive Controls for Human Food. Organic certification does not automatically confer FSMA compliance.',
    `globalg_ap_certified_flag` BOOLEAN COMMENT 'Indicates whether the operation holds concurrent GLOBALG.A.P. (Global Good Agricultural Practices) certification in addition to USDA NOP organic certification. GLOBALG.A.P. certification is often required by major retail buyers and export markets.',
    `gmo_free_flag` BOOLEAN COMMENT 'Indicates whether the certified operation and its products are verified as free from Genetically Modified Organisms (GMOs). USDA NOP prohibits the use of excluded methods including genetic engineering; this flag confirms GMO-free status as part of organic compliance.',
    `international_equivalency_flag` BOOLEAN COMMENT 'Indicates whether this certification is recognized under an international organic equivalency arrangement (e.g., USDA-EU Organic Equivalency Agreement, USDA-Canada Organic Equivalency Arrangement). Enables certified organic products to be sold as organic in partner countries without additional certification.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent on-site inspection conducted by the certifying agent at the certified operation. Annual on-site inspections are required under USDA NOP to verify compliance with organic standards.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this organic certification record was most recently modified. Tracks changes to certification status, renewal events, suspension/revocation actions, and document updates for audit and compliance purposes.',
    `next_inspection_date` DATE COMMENT 'Scheduled date for the next on-site inspection by the certifying agent. Used for compliance planning and operational readiness to ensure the operation is prepared for the annual NOP inspection.',
    `nop_system_plan_reference` STRING COMMENT 'Document reference number or identifier for the Organic System Plan (OSP) submitted to and approved by the certifying agent. The OSP is the foundational compliance document describing all practices, materials, and monitoring activities for the certified operation.',
    `notes` STRING COMMENT 'Free-text field for additional remarks, conditions, or special provisions associated with this organic certification record. May include certifying agent conditions, corrective action requirements, or operational notes relevant to compliance management.',
    `operation_name` STRING COMMENT 'The legal name of the certified organic operation (farm, ranch, or handling facility) as it appears on the organic certificate. This is the entity name recognized by the certifying agent and USDA NOP for compliance purposes.',
    `operation_type` STRING COMMENT 'Classification of the certified organic operation type. Producer: farms and ranches growing organic crops or raising organic livestock. Handler: facilities processing or packaging organic products. Broker: entities buying and selling organic products. Importer: entities importing certified organic products. Distributor: entities distributing certified organic products.. Valid values are `producer|handler|broker|importer|distributor`',
    `organic_label_type` STRING COMMENT 'The USDA NOP-defined organic labeling category authorized for products under this certification. 100_percent_organic: all ingredients are certified organic. Organic: at least 95% certified organic ingredients. Made_with_organic: 70-95% certified organic ingredients. Organic_ingredients: less than 70% organic, may list specific organic ingredients. Determines permissible label claims and USDA Organic Seal usage.. Valid values are `100_percent_organic|organic|made_with_organic|organic_ingredients`',
    `premium_pricing_eligible_flag` BOOLEAN COMMENT 'Indicates whether products covered by this certification are currently eligible for organic premium pricing in sales and distribution channels. Eligibility requires active certification status and valid organic label type authorization.',
    `renewal_due_date` DATE COMMENT 'The deadline by which the annual renewal application and supporting documentation must be submitted to the certifying agent to maintain uninterrupted organic certification status.',
    `revocation_date` DATE COMMENT 'The date on which the organic certification was permanently revoked by the certifying agent. Populated only when certification_status is revoked. Revocation is the most severe enforcement action and prohibits the operation from making organic claims.',
    `revocation_reason` STRING COMMENT 'Narrative description of the reason for permanent revocation of the organic certification. Documents the specific violation or fraudulent activity that resulted in the certifying agent revoking the certificate.',
    `suspension_date` DATE COMMENT 'The date on which the organic certification was suspended by the certifying agent. Populated only when certification_status is suspended. Suspension may result from non-compliance findings, use of prohibited substances, or failure to submit required documentation.',
    `suspension_reason` STRING COMMENT 'Narrative description of the reason for suspension of the organic certification. Documents the specific non-compliance finding or violation that triggered the suspension action by the certifying agent.',
    `transition_complete_flag` BOOLEAN COMMENT 'Indicates whether the mandatory 36-month organic transition period has been completed for the land or operation covered by this certification. True indicates the operation has fulfilled the transition requirement and is eligible for full organic certification.',
    `transition_start_date` DATE COMMENT 'The date on which the operation began the mandatory 36-month transition period required before land can be certified organic under USDA NOP. During transition, no prohibited substances may be applied to the land.',
    CONSTRAINT pk_organic_certification PRIMARY KEY(`organic_certification_id`)
) COMMENT 'Tracks USDA National Organic Program (NOP) organic certification records for products, product lines, and production operations. Captures certifying agent name, certificate number, certification scope (crops, livestock, handling/processing), certification effective date, expiration date, annual renewal status, allowed materials list, and any suspension or revocation events. Links products to their certified organic status and supports COOL and organic labeling compliance. Required for organic premium pricing and retail organic claims.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`product`.`gmo_declaration` (
    `gmo_declaration_id` BIGINT COMMENT 'Unique system-generated identifier for each GMO declaration record. Primary key for the gmo_declaration data product.',
    `master_id` BIGINT COMMENT 'Reference to the agricultural product or commodity for which this GMO declaration is recorded. Links to the product catalog master.',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: gmo_declaration.organic_certified_flag and organic_certificate_number indicate that a GMO declaration may reference an associated organic certification (non-GMO products are often also organically cer',
    `aphis_petition_number` STRING COMMENT 'APHIS petition number associated with the deregulation or regulatory approval of the specific bioengineered trait or transformation event. Used to verify US market approval status and cross-reference APHIS regulatory records.. Valid values are `^[0-9]{2}-[0-9]{3}-[0-9]{2}[p]?$`',
    `be_disclosure_required_flag` BOOLEAN COMMENT 'Indicates whether this product requires Bioengineered (BE) food disclosure labeling under the USDA National Bioengineered Food Disclosure Standard (NBFDS). Drives label generation and compliance workflows.',
    `be_disclosure_type` STRING COMMENT 'Method of BE food disclosure used on product labeling as required by USDA NBFDS. Options include on-package text, USDA BE symbol, electronic/digital link (QR code), or phone number. not_required when product is exempt.. Valid values are `text|symbol|electronic_qr|phone_number|not_required`',
    `certificate_expiry_date` DATE COMMENT 'Date on which the non-GMO certificate or GMO verification certificate expires and must be renewed. Drives compliance monitoring and re-certification workflows.',
    `china_market_approved_flag` BOOLEAN COMMENT 'Indicates whether this GMO transformation event has received regulatory approval for import or commercial use in China. Required for export documentation to Chinese buyers and compliance with MARA (Ministry of Agriculture and Rural Affairs) biosafety certificates.',
    `coa_reference` STRING COMMENT 'Reference number or document identifier for the Certificate of Analysis (COA) associated with this GMO declaration. The COA contains the full laboratory test results and is provided to customers and regulatory bodies.',
    `cool_country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code indicating the country of origin of the product as required for Country of Origin Labeling (COOL) compliance. Relevant for GMO declarations as country of origin may affect applicable GMO regulations.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp recording when this GMO declaration record was first created in the data platform. Used for audit trail and data lineage tracking.',
    `declaration_date` DATE COMMENT 'Date on which the GMO declaration was formally submitted or issued. Represents the principal business event date for this record, distinct from system audit timestamps.',
    `declaration_number` STRING COMMENT 'Externally-known unique business identifier for this GMO declaration record, used in regulatory submissions, export documentation, and audit trails. Follows internal numbering convention (e.g., GMO-2024-00123).. Valid values are `^GMO-[A-Z0-9]{4,20}$`',
    `declaration_status` STRING COMMENT 'Current lifecycle status of the GMO declaration record. Tracks the workflow from initial draft through regulatory review to approval, expiry, or withdrawal. [ENUM-REF-CANDIDATE: draft|pending_review|approved|rejected|expired|withdrawn — promote to reference product]. Valid values are `draft|pending_review|approved|rejected|expired|withdrawn`',
    `declared_by` STRING COMMENT 'Name or identifier of the person or organization responsible for submitting this GMO declaration. Used for accountability, audit trail, and regulatory compliance documentation.',
    `donor_organism` STRING COMMENT 'Scientific name of the organism from which the introduced genetic material was derived (e.g., Agrobacterium tumefaciens, Bacillus thuringiensis). Required for regulatory submissions and export documentation.',
    `eu_market_approved_flag` BOOLEAN COMMENT 'Indicates whether this GMO transformation event has received regulatory approval for commercial use or import in the European Union. Critical for export compliance and trade documentation.',
    `gmo_status` STRING COMMENT 'Declared GMO classification of the product. bioengineered aligns with USDA BE disclosure requirements. non_gmo indicates verified absence of bioengineered material. conventional indicates no GMO testing performed. under_assessment indicates testing in progress.. Valid values are `bioengineered|non_gmo|conventional|under_assessment`',
    `gmo_threshold_percent` DECIMAL(18,2) COMMENT 'Maximum allowable percentage of GMO material for the product to be classified as non-GMO or to meet the applicable regulatory threshold for the target market (e.g., 0.9% for EU, 5.0% for Japan). Drives compliance determination logic.',
    `introduced_gene` STRING COMMENT 'Name of the gene or genetic construct introduced into the organism (e.g., cp4 epsps, cry1Ab, bar). Used for scientific documentation, regulatory submissions, and export market approval cross-referencing.',
    `ip_protocol_reference` STRING COMMENT 'Reference code or document identifier for the Identity Preservation (IP) protocol applied to maintain the segregation and traceability of non-GMO or specific GMO product streams throughout the supply chain. Supports USDA BE disclosure and export market requirements.',
    `japan_market_approved_flag` BOOLEAN COMMENT 'Indicates whether this GMO transformation event has received regulatory approval for import or commercial use in Japan. Required for export documentation to Japanese buyers under Japans Food Safety Commission GMO approval framework.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'System timestamp recording when this GMO declaration record was most recently modified. Used for change tracking, audit compliance, and data freshness monitoring.',
    `non_gmo_certificate_number` STRING COMMENT 'Certificate or verification number issued by the non-GMO verification body. Used for audit trail, customer documentation, and regulatory compliance. Null when no third-party verification exists.',
    `non_gmo_verification_body` STRING COMMENT 'Name of the third-party organization that verified and certified the non-GMO status of the product (e.g., Non-GMO Project, USDA Organic NOP). Applicable only when gmo_status is non_gmo. none indicates no third-party verification.. Valid values are `Non-GMO Project|USDA Organic|EU Non-GMO|ProTerra|CERT ID|none`',
    `organic_certified_flag` BOOLEAN COMMENT 'Indicates whether the product holds USDA National Organic Program (NOP) certification. Organic certification inherently prohibits GMO use; this flag supports cross-validation of GMO status against organic certification status.',
    `remarks` STRING COMMENT 'Free-text field for additional notes, qualifications, or explanations related to the GMO declaration. May include details on testing anomalies, conditional approvals, or market-specific exceptions.',
    `review_date` DATE COMMENT 'Date on which the GMO declaration was reviewed and approved or rejected by the responsible quality or regulatory team. Supports workflow tracking and audit compliance.',
    `reviewer_name` STRING COMMENT 'Name of the quality assurance or regulatory compliance officer who reviewed and approved or rejected this GMO declaration. Required for audit trail and SOX compliance.',
    `sample_lot_number` STRING COMMENT 'Lot or batch number of the product sample submitted for GMO testing. Enables traceability from the GMO declaration back to the specific production lot for recall management and audit purposes.',
    `test_result_percent` DECIMAL(18,2) COMMENT 'Quantitative result of GMO testing expressed as a percentage of GMO material detected in the sample (e.g., 0.0500 = 0.05%). Used to assess compliance against regulatory thresholds (e.g., EU 0.9% labeling threshold, Japan 5% threshold).',
    `testing_laboratory` STRING COMMENT 'Name of the accredited laboratory that performed GMO testing on the product. Must be an ISO 17025-accredited laboratory for regulatory acceptance of results.',
    `testing_method` STRING COMMENT 'Laboratory method used to test for the presence or absence of GMO material in the product (e.g., PCR - Polymerase Chain Reaction, ELISA - Enzyme-Linked Immunosorbent Assay). not_tested when no laboratory testing was performed.. Valid values are `PCR|ELISA|lateral_flow|strip_test|DNA_sequencing|not_tested`',
    `threshold_jurisdiction` STRING COMMENT 'Jurisdiction or market for which the gmo_threshold_percent applies. Uses ISO 3166-1 alpha-3 country codes or global for internationally harmonized thresholds. Enables multi-market compliance management. [ENUM-REF-CANDIDATE: USA|EU|CHN|JPN|BRA|CAN|AUS|global — 8 candidates stripped; promote to reference product]',
    `trait_description` STRING COMMENT 'Descriptive name and functional summary of the introduced genetic trait (e.g., Herbicide tolerance - glyphosate, Insect resistance - Bt Cry1Ab protein, Drought tolerance - DREB transcription factor). Supports product labeling, COA documentation, and export market compliance.',
    `us_market_approved_flag` BOOLEAN COMMENT 'Indicates whether this GMO transformation event has received regulatory approval for commercial use in the United States market. Verified against APHIS deregulation status and FDA/EPA approvals.',
    `verification_date` DATE COMMENT 'Date on which GMO status was verified through testing, certification, or third-party audit. Used to determine currency of the declaration and trigger re-verification workflows.',
    CONSTRAINT pk_gmo_declaration PRIMARY KEY(`gmo_declaration_id`)
) COMMENT 'Records GMO status declarations and non-GMO verification records for agricultural products and commodities. Captures GMO trait description, transformation event identifier (APHIS petition number), approved market status by jurisdiction (US, EU, China), non-GMO verification body (Non-GMO Project, USDA Organic), identity preservation (IP) protocol reference, and testing/verification date. Supports USDA BE (Bioengineered Food Disclosure) labeling compliance and export market GMO documentation requirements.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`product`.`grading_standard` (
    `grading_standard_id` BIGINT COMMENT 'Unique surrogate identifier for each grading standard record in the agricultural product catalog. Primary key for the grading_standard reference entity.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: grading_standard is defined for specific commodity types (e.g., USDA Grade No. 1 Hard Red Winter Wheat). grading_standard.commodity_name is a denormalized string reference to the commodity catalog. Ad',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: grading_standard currently stores mrl_threshold_ppm as a denormalized DECIMAL scalar. The mrl_threshold table is the authoritative SSOT for Maximum Residue Limits. A grading standard for an agricultur',
    `administering_agency` STRING COMMENT 'Federal agency responsible for administering and enforcing this grading standard (e.g., AMS - Agricultural Marketing Service, GIPSA - Grain Inspection Packers and Stockyards Administration, FSIS - Food Safety and Inspection Service). Determines inspection authority and regulatory citation. [ENUM-REF-CANDIDATE: AMS|GIPSA|FSIS|APHIS|FDA|EPA|NOP — 7 candidates stripped; promote to reference product]',
    `applicable_market_class` STRING COMMENT 'Market class or sub-class of the commodity to which this grading standard applies (e.g., Hard Red Winter, Soft White, Yellow Dent Corn, Angus Beef). Provides finer commodity segmentation within the commodity type for accurate grade assignment.',
    `coa_template_reference` STRING COMMENT 'Reference identifier for the COA document template associated with this grading standard. Used by quality inspection workflows in SAP QM to auto-populate COA documents upon grade assignment.',
    `color_requirement` STRING COMMENT 'Descriptive color specification or color score range required for this grade designation (e.g., minimum 50% red color for US Extra Fancy apples, bright yellow for US No. 1 corn). Applies primarily to produce and livestock grading per USDA AMS standards.',
    `commodity_type` STRING COMMENT 'Broad commodity category to which this grading standard applies (e.g., grain, oilseed, produce, fiber, livestock, dairy, poultry, egg, processed). Aligns with USDA commodity classification for routing to the correct inspection workflow. [ENUM-REF-CANDIDATE: grain|oilseed|produce|fiber|livestock|dairy|poultry|egg|processed — 9 candidates stripped; promote to reference product]',
    `cool_required_flag` BOOLEAN COMMENT 'Indicates whether Country of Origin Labeling (COOL) is required for products graded under this standard. When True, COA and product labeling must include country of origin per USDA AMS COOL regulations.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this grading standard record was first created in the system. Supports audit trail and data lineage requirements per SOX and FSMA compliance frameworks.',
    `effective_date` DATE COMMENT 'Date on which this grading standard became or becomes officially effective and enforceable. Used to determine applicability during quality inspection and COA generation workflows.',
    `expiry_date` DATE COMMENT 'Date on which this grading standard expires or is superseded. Null indicates the standard is open-ended with no scheduled expiration. Used to enforce version control in quality inspection workflows.',
    `foreign_material_max_pct` DECIMAL(18,2) COMMENT 'Maximum allowable percentage of foreign material (non-commodity matter) permitted for this grade designation. A standard GIPSA grading factor for grains, oilseeds, and other bulk commodities.',
    `gfsi_scheme_alignment` STRING COMMENT 'Identifies the GFSI-recognized food safety scheme (e.g., SQF, BRC, IFS, GLOBALG.A.P., FSSC 22000) with which this grading standard is aligned or compatible. Supports customer audit and certification requirements.. Valid values are `SQF|BRC|IFS|GLOBALG.A.P.|FSSC22000|none`',
    `gmo_applicability` STRING COMMENT 'Indicates whether this grading standard applies to GMO products, non-GMO products, or both. Supports product line segregation for non-GMO and conventional product lines per USDA and GLOBALG.A.P. requirements.. Valid values are `gmo|non_gmo|both`',
    `grade_designation` STRING COMMENT 'Official grade label assigned by the administering agency (e.g., US No. 1, US No. 2, US Extra Fancy, USDA Prime, USDA Choice, US Grade A). Represents the quality tier within the standard. [ENUM-REF-CANDIDATE: US No. 1|US No. 2|US No. 3|US Extra Fancy|USDA Prime|USDA Choice|USDA Select|US Grade A|US Grade B|US Grade C — promote to reference product]',
    `grading_method` STRING COMMENT 'Primary method used to assess and assign this grade (e.g., visual inspection, mechanical sizing, laboratory analysis, electronic/NIR sensing, or a combination). Determines inspection workflow and equipment requirements in SAP QM and field operations.. Valid values are `visual|mechanical|laboratory|electronic|combined`',
    `inspection_frequency` STRING COMMENT 'Required frequency of grading inspections for commodities subject to this standard (e.g., per lot, per shipment, per batch, periodic, continuous). Drives quality inspection scheduling in SAP QM and Manhattan WMS workflows.. Valid values are `per_lot|per_shipment|per_batch|periodic|continuous`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this grading standard record was most recently modified. Used for change tracking, data synchronization with SAP QM, and regulatory audit trail maintenance.',
    `moisture_content_max_pct` DECIMAL(18,2) COMMENT 'Maximum allowable moisture content (%) for a commodity to qualify for this grade designation. A critical grading criterion for grains and oilseeds per GIPSA standards. Exceeding this threshold results in grade reduction or rejection.',
    `notes` STRING COMMENT 'Free-text field for additional remarks, special conditions, or clarifications related to this grading standard (e.g., seasonal applicability, regional exceptions, special handling requirements). Used by quality and compliance teams.',
    `organic_eligible_flag` BOOLEAN COMMENT 'Indicates whether this grading standard is applicable to USDA National Organic Program (NOP) certified organic products. When True, the standard supports organic product line quality certification and COA generation.',
    `publication_date` DATE COMMENT 'Date on which this grading standard was officially published in the Federal Register or by the administering agency. Distinct from the effective date; used for regulatory audit trails and compliance documentation.',
    `regulation_citation` STRING COMMENT 'Official regulatory citation for the grading standard, including CFR title, part, and section (e.g., 7 CFR Part 26, 7 CFR Part 868, 9 CFR Part 319). Required for COA generation and FSMA compliance documentation.',
    `serious_defects_max_pct` DECIMAL(18,2) COMMENT 'Maximum allowable percentage of serious defects (e.g., heat-damaged kernels, mold, insect damage) permitted for this grade. Serious defects are a distinct sub-category of total defects with stricter tolerance limits per GIPSA standards.',
    `size_requirement` STRING COMMENT 'Size specification or size range required for this grade designation (e.g., minimum diameter in mm, weight per unit, count per carton). Applies to produce, eggs, and livestock products per USDA AMS grading standards.',
    `standard_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the grading standard (e.g., USDA-GR1-CORN, AMS-EF-APPLE). Used as the business key for cross-system reference and COA generation.. Valid values are `^[A-Z0-9-]{2,30}$`',
    `standard_document_url` STRING COMMENT 'URL link to the official published grading standard document on the administering agencys website (e.g., USDA AMS, GIPSA). Provides direct access to the authoritative source document for quality inspectors and compliance teams.. Valid values are `^https?://.+$`',
    `standard_name` STRING COMMENT 'Full descriptive name of the grading standard as published by the administering agency (e.g., United States Standards for Grades of Corn, USDA Extra Fancy Grade for Apples). Used in COA documentation and quality inspection workflows.',
    `standard_status` STRING COMMENT 'Current lifecycle status of the grading standard. active indicates the standard is currently in force; superseded indicates replaced by a newer version; withdrawn indicates no longer applicable; draft or pending indicates under review or awaiting official publication.. Valid values are `active|superseded|withdrawn|draft|pending`',
    `superseded_by_code` STRING COMMENT 'Standard code of the newer grading standard that replaces this record when status is superseded. Enables forward navigation in the version chain for compliance and historical reporting.',
    `test_weight_min_lbs_bu` DECIMAL(18,2) COMMENT 'Minimum test weight in pounds per bushel (lbs/bu) required for a grain or oilseed commodity to qualify for this grade. Test weight is a key GIPSA grading factor reflecting grain density and quality.',
    `total_defects_max_pct` DECIMAL(18,2) COMMENT 'Maximum allowable percentage of total defects (damaged kernels, heat damage, broken kernels, etc.) permitted for this grade designation. Applies to grain, oilseed, and produce grading per GIPSA and AMS standards.',
    `usda_commodity_code` STRING COMMENT 'Official USDA commodity code associated with this grading standard, enabling alignment with USDA AMS, GIPSA, and WASDE reporting systems. Used for regulatory reporting and supply chain traceability.. Valid values are `^[0-9]{4,10}$`',
    `version_number` STRING COMMENT 'Version or revision number of the grading standard as published by the administering agency (e.g., 1.0, 2023, 3). Supports audit trails and historical compliance verification.. Valid values are `^[0-9]{1,4}(.[0-9]{1,4})?$`',
    CONSTRAINT pk_grading_standard PRIMARY KEY(`grading_standard_id`)
) COMMENT 'Reference catalog of all applicable grading standards and grade specifications for agricultural commodities and products. Captures USDA grade designation (e.g., US No. 1, US Extra Fancy, USDA Prime), commodity type, grading criteria (moisture content, test weight, foreign material tolerance, defect limits), applicable regulation citation, effective date, and administering agency (AMS, FSIS, GIPSA). Supports quality inspection workflows and COA generation. Aligned with USDA AMS and GIPSA official grade standards.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`product`.`mrl_threshold` (
    `mrl_threshold_id` BIGINT COMMENT 'Unique system-generated identifier for each MRL threshold record in the regulatory reference catalog. Primary key for this table.',
    `active_ingredient_cas_number` STRING COMMENT 'CAS Registry Number uniquely identifying the pesticide active ingredient chemical substance. Enables unambiguous cross-referencing across regulatory databases and SDS documentation.. Valid values are `^[0-9]{2,7}-[0-9]{2}-[0-9]$`',
    `active_ingredient_name` STRING COMMENT 'Common or IUPAC chemical name of the pesticide active ingredient (AI) for which the MRL is established. Used to cross-reference against agrochemical product labels and COA verification.',
    `analytical_method_reference` STRING COMMENT 'Reference to the validated analytical method (e.g., AOAC, EN, EPA method number) used for laboratory detection and quantification of the residue to verify compliance with this MRL. Supports COA and laboratory accreditation alignment.',
    `application_method` STRING COMMENT 'Method of pesticide application for which this MRL tolerance is established (e.g., foliar spray, soil application, seed treatment, post-harvest treatment, fumigation). Affects residue behavior and PHI calculation.. Valid values are `foliar|soil|seed_treatment|post_harvest|fumigation|systemic`',
    `codex_reference_number` STRING COMMENT 'Official Codex Alimentarius MRL reference number (CXL number) for this tolerance, enabling direct cross-reference to the Codex MRL database. Used for international trade documentation and export COA verification.',
    `commodity_group` STRING COMMENT 'Broader commodity group classification under which the specific commodity falls (e.g., cereal grains, fruiting vegetables, root and tuber vegetables, meat and poultry). Supports group tolerance application per EPA and Codex rules.',
    `commodity_part` STRING COMMENT 'Specific part of the commodity to which the MRL applies (e.g., whole commodity, edible portion only, peel, grain, muscle tissue, fat, liver, milk, eggs). Relevant for processed commodity tolerances and animal product MRLs. [ENUM-REF-CANDIDATE: whole_commodity|edible_portion|peel|seed|grain|muscle|fat|liver|kidney|milk|eggs — 11 candidates stripped; promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this MRL threshold record was first created in the system. Supports data lineage, audit trail, and Silver layer ingestion tracking per Databricks Lakehouse governance standards.',
    `data_source` STRING COMMENT 'Originating regulatory database or system from which this MRL record was sourced (e.g., EPA Office of Pesticide Programs tolerance database, Codex MRL database, EU Pesticides database). Supports data lineage and refresh cycle management.. Valid values are `EPA_OPP|CODEX_MRL_DB|EU_PESTICIDES_DB|PMRA_CANADA|APVMA_AUSTRALIA|MHLW_JAPAN`',
    `default_mrl_flag` BOOLEAN COMMENT 'Indicates whether this MRL is a default/general tolerance applied in the absence of a specific established tolerance (e.g., Codex default of 0.01 ppm, EU default of 0.01 ppm under Regulation EC 396/2005). True = default MRL applies; False = specific established tolerance.',
    `effective_date` DATE COMMENT 'Date on which this MRL tolerance became legally effective and enforceable by the regulatory jurisdiction. Used to determine applicability for current crop season compliance and PHI scheduling.',
    `epa_registration_number` STRING COMMENT 'EPA pesticide registration number associated with the active ingredient or product formulation. Links MRL tolerance to the registered pesticide product for PHI compliance and export documentation.. Valid values are `^[0-9]{5}-[0-9]{3,5}(-[0-9]{2,5})?$`',
    `exemption_reason` STRING COMMENT 'Regulatory justification for a tolerance exemption, applicable when tolerance_type is exemption. Describes why the active ingredient is exempt from MRL requirements (e.g., naturally occurring substance, minimal risk, biochemical pesticide). Null for non-exemption tolerance types.',
    `expiry_date` DATE COMMENT 'Date on which this MRL tolerance expires or is scheduled for revocation. Null for indefinite tolerances. Critical for time-limited emergency exemptions (Section 18) and temporary import tolerances.',
    `federal_register_citation` STRING COMMENT 'U.S. Federal Register citation (volume, page number, and date) for the EPA final rule establishing or amending this tolerance. Provides regulatory traceability for audit and legal compliance purposes.',
    `gmo_applicability_flag` BOOLEAN COMMENT 'Indicates whether this MRL tolerance specifically applies to or was established in the context of GMO crop varieties (e.g., herbicide-tolerant GMO crops with higher herbicide residue tolerances). True = GMO-specific tolerance; False = applies to conventional and GMO equally.',
    `import_tolerance_flag` BOOLEAN COMMENT 'Indicates whether this MRL was established specifically as an import tolerance to facilitate trade for commodities treated with a pesticide not registered domestically. True = import tolerance; False = domestic tolerance. Relevant for FOB/CIF export documentation.',
    `jurisdiction_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code for the importing or regulating country associated with this MRL. Used for export eligibility checks and Country of Origin Labeling (COOL) compliance. Null for multi-country jurisdictions (e.g., EU, Codex).. Valid values are `^[A-Z]{3}$`',
    `last_reviewed_date` DATE COMMENT 'Date on which this MRL record was last reviewed and confirmed against the authoritative regulatory source database. Supports data quality management and ensures currency of compliance reference data.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this MRL threshold record was most recently modified. Used for incremental data refresh, change detection, and regulatory data currency validation in the Databricks Silver layer.',
    `limit_of_quantification_ppm` DECIMAL(18,2) COMMENT 'Lowest concentration of the active ingredient residue that can be reliably quantified by the validated analytical method. Used to determine whether a non-detect result constitutes MRL compliance, particularly for default MRL tolerances.',
    `mode_of_action_code` STRING COMMENT 'IRAC (Insecticide Resistance Action Committee), FRAC (Fungicide Resistance Action Committee), or HRAC (Herbicide Resistance Action Committee) mode of action classification code for the active ingredient. Supports IPM resistance management planning.',
    `mrl_value_ppm` DECIMAL(18,2) COMMENT 'The established maximum residue limit expressed in parts per million (ppm, equivalent to mg/kg) for the active ingredient on the specified commodity. Core compliance threshold used for COA verification, pre-harvest interval enforcement, and export eligibility determination.',
    `notes` STRING COMMENT 'Free-text field for additional regulatory notes, conditions, or qualifications associated with this MRL tolerance (e.g., specific use restrictions, footnotes from regulatory publications, pending review status, or special conditions for application).',
    `organic_approved_flag` BOOLEAN COMMENT 'Indicates whether the active ingredient is approved for use in certified organic production under USDA National Organic Program (NOP) standards. True = approved for organic use; False = not approved. Supports organic product line compliance and NOP certification maintenance.',
    `phi_days` STRING COMMENT 'Minimum number of days required between the last pesticide application and harvest to ensure residues do not exceed the MRL at time of harvest. Critical for crop protection scheduling and FSMA compliance. Sourced from EPA label requirements.',
    `processing_factor` DECIMAL(18,2) COMMENT 'Ratio of residue concentration in the processed commodity to residue concentration in the raw agricultural commodity (RAC). Used to calculate MRL compliance for processed food products derived from the raw commodity. Values >1 indicate concentration; values <1 indicate reduction.',
    `regulatory_jurisdiction` STRING COMMENT 'The regulatory authority or jurisdiction that established this MRL (e.g., US_EPA for United States Environmental Protection Agency, EU for European Union Regulation EC 396/2005, CODEX for Codex Alimentarius Commission). Critical for export documentation and multi-market compliance. [ENUM-REF-CANDIDATE: US_EPA|EU|CODEX|CANADA|JAPAN|AUSTRALIA|CHINA|BRAZIL|MEXICO|KOREA|INDIA|TAIWAN — promote to reference product]',
    `residue_definition` STRING COMMENT 'Regulatory definition of what constitutes the measurable residue for enforcement purposes, including parent compound and relevant metabolites or degradation products. Critical for laboratory COA analysis method alignment.',
    `revocation_date` DATE COMMENT 'Date on which a previously established MRL tolerance was formally revoked or cancelled by the regulatory authority. Null for active tolerances. Supports historical compliance audit trails and COA re-verification.',
    `source_record_reference` STRING COMMENT 'Native record identifier from the originating regulatory database (e.g., EPA tolerance petition number, Codex CXL reference, EU database entry ID). Enables traceability back to the authoritative source system for audit and refresh purposes.',
    `tolerance_status` STRING COMMENT 'Current lifecycle status of the MRL tolerance record: active for currently enforceable tolerances, revoked for cancelled tolerances, expired for time-limited tolerances past their expiry date, pending for proposed tolerances under regulatory review, suspended for temporarily suspended tolerances.. Valid values are `active|revoked|expired|pending|suspended`',
    `tolerance_type` STRING COMMENT 'Classification of the MRL tolerance type: established for standard EPA/Codex tolerances, exemption for active ingredients exempt from tolerance requirements, import_tolerance for tolerances set specifically for imported commodities, emergency_exemption for Section 18 emergency use tolerances, group_tolerance for tolerances covering a commodity group.. Valid values are `established|exemption|import_tolerance|emergency_exemption|group_tolerance`',
    CONSTRAINT pk_mrl_threshold PRIMARY KEY(`mrl_threshold_id`)
) COMMENT 'Reference table of Maximum Residue Limits (MRL) for pesticide active ingredients (AI) on specific agricultural commodities by regulatory jurisdiction. Captures active ingredient name, EPA registration number, commodity or commodity group, MRL value (ppm), regulatory jurisdiction (US EPA, EU, Codex Alimentarius, importing country), effective date, and tolerance type (established, exemption, import tolerance). Critical for pre-harvest interval (PHI) compliance, export documentation, and COA verification. Sourced from EPA and Codex Alimentarius databases.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`product`.`label` (
    `label_id` BIGINT COMMENT 'Unique system-generated identifier for each label record in the agricultural product labeling catalog. Primary key for the label data product.',
    `gmo_declaration_id` BIGINT COMMENT 'Foreign key linking to product.gmo_declaration. Business justification: label currently has a non_gmo_claim_flag (BOOLEAN) that indicates a non-GMO claim on the label but provides no traceability to the supporting declaration. Under USDA Bioengineered (BE) Disclosure regu',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: label.usda_grade_designation is a denormalized string reference to the applicable USDA grade standard displayed on the label. Adding grading_standard_id FK normalizes this to the authoritative grading',
    `master_id` BIGINT COMMENT 'Reference to the agricultural product or commodity this label is associated with in the product catalog (crop commodity, livestock product, processed good, seed/input, or value-added product).',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: label.mrl_compliance_flag indicates whether the label is MRL-compliant, but there is no reference to the specific MRL threshold being complied with. Adding mrl_threshold_id FK links the label to the a',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: label.organic_certification_code is a denormalized string reference to the NOP organic certification that authorizes the organic seal on the label. Adding organic_certification_id FK normalizes this t',
    `allergen_cross_contact_risk` STRING COMMENT 'Assessed risk level for unintentional allergen cross-contact during production, handling, or packaging. Drives may contain advisory statement decisions and HACCP allergen control plan requirements.. Valid values are `none|low|medium|high`',
    `allergen_milk_flag` BOOLEAN COMMENT 'Indicates whether milk (FDA Big 9 allergen) is intentionally included as an ingredient in this product. When True, milk must be declared in the ingredient list and allergen statement per FALCPA.',
    `allergen_soy_flag` BOOLEAN COMMENT 'Indicates whether soybeans (FDA Big 9 allergen) are intentionally included as an ingredient. Particularly relevant in agricultural products given soys prevalence in processed and feed products.',
    `allergen_wheat_flag` BOOLEAN COMMENT 'Indicates whether wheat (FDA Big 9 allergen) is intentionally included as an ingredient. When True, wheat must be declared in the ingredient list and allergen statement per FALCPA.',
    `applicable_markets` STRING COMMENT 'Comma-separated list of ISO 3166-1 alpha-3 country codes or market identifiers for which this label version is approved and valid (e.g., USA,CAN,MEX). Supports multi-market label management and export compliance.',
    `artwork_file_reference` STRING COMMENT 'File path, document management system reference, or URI pointing to the approved label artwork file (e.g., PDF, AI, EPS). Supports label artwork version control and print production workflows.',
    `calories_per_serving` STRING COMMENT 'Total caloric value per serving as declared on the Nutrition Facts panel, expressed in kilocalories (kcal). Calculated from macronutrient composition per FDA rounding rules.',
    `cool_designation` STRING COMMENT 'Country of origin declaration required under COOL (Country of Origin Labeling) regulations. Specifies the country or countries where the product was produced, grown, or processed. Uses ISO 3166-1 alpha-3 country codes (e.g., USA, MEX, CAN).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this label record was first created in the system. Supports audit trail, data lineage, and regulatory record-keeping requirements.',
    `effective_date` DATE COMMENT 'Date on which this label version becomes commercially active and legally binding for product packaging and distribution. Aligns with regulatory approval and market launch timelines.',
    `expiry_date` DATE COMMENT 'Date on which this label version is no longer valid for use on new production runs. Null for open-ended approvals. Triggers label review and renewal workflows.',
    `haccp_allergen_control_plan_ref` STRING COMMENT 'Reference identifier for the HACCP allergen control plan document governing allergen management for this product label. Links label allergen declarations to the facilitys preventive controls documentation.',
    `ingredient_statement` STRING COMMENT 'Full ingredient list as it appears on the label, listed in descending order of predominance by weight. Must comply with FDA 21 CFR Part 101.4 ingredient declaration requirements.',
    `label_code` STRING COMMENT 'Externally-known unique alphanumeric code assigned to this label version, used for cross-referencing with SAP QM label management and regulatory submission tracking.. Valid values are `^LBL-[A-Z0-9]{4,20}$`',
    `label_name` STRING COMMENT 'Human-readable descriptive name of the label, typically reflecting the product name, market, and version (e.g., Organic Whole Wheat Flour — US Retail v3).',
    `label_status` STRING COMMENT 'Current lifecycle state of the label record. Tracks progression from draft through regulatory approval to active use, supersession by a newer version, or withdrawal from market.. Valid values are `draft|pending_approval|approved|active|superseded|withdrawn`',
    `label_type` STRING COMMENT 'Classification of the label by its intended commercial use channel: retail consumer packaging, foodservice bulk, export market, private label, or ingredient/intermediate product.. Valid values are `retail|foodservice|bulk|export|private_label|ingredient`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this label record. Used for change tracking, audit compliance, and downstream data synchronization.',
    `mrl_compliance_flag` BOOLEAN COMMENT 'Indicates whether this labels associated product has been verified to comply with applicable Maximum Residue Limit (MRL) thresholds for pesticide and agrochemical residues as set by EPA, Codex Alimentarius, or destination market regulators.',
    `net_weight_declaration` STRING COMMENT 'Mandatory net weight or net quantity statement as it appears on the label (e.g., 5 LB (2.27 kg), 16 FL OZ (473 mL)). Must comply with NIST Handbook 133 and FDA net quantity of contents regulations.',
    `nutrition_analysis_method` STRING COMMENT 'Method used to determine the nutrition facts panel values: laboratory analysis (wet chemistry), nutrient database calculation (USDA FoodData Central), recipe calculation, or a combination. Affects accuracy and regulatory defensibility.. Valid values are `laboratory_analysis|database_calculation|recipe_calculation|combination`',
    `organic_seal_authorized` BOOLEAN COMMENT 'Indicates whether this label is authorized to display the USDA Organic seal under the National Organic Program (NOP). True only when the product and operation hold valid NOP certification.',
    `plu_code` STRING COMMENT '4 or 5-digit Price Look-Up (PLU) code used for fresh produce identification at retail point-of-sale. Assigned by the International Federation for Produce Standards (IFPS). Applicable to fresh fruit, vegetable, and herb products.. Valid values are `^[0-9]{4,5}$`',
    `protein_g` DECIMAL(18,2) COMMENT 'Protein content per serving in grams as declared on the Nutrition Facts panel. Mandatory declaration on FDA Nutrition Facts label.',
    `regulatory_approval_reference` STRING COMMENT 'Official reference number or tracking code issued by the regulatory authority (e.g., USDA AMS label approval number, FDA submission reference) confirming this label has been reviewed and authorized.',
    `serving_size_description` STRING COMMENT 'Serving size as declared on the Nutrition Facts panel (e.g., 1 cup (240g), 2 tablespoons (32g)). Must align with FDA Reference Amounts Customarily Consumed (RACC) for the product category.',
    `servings_per_container` DECIMAL(18,2) COMMENT 'Number of servings per container as declared on the Nutrition Facts panel. May be a whole number or decimal (e.g., 2.5 servings). Required for FDA-compliant Nutrition Facts labeling.',
    `sodium_mg` DECIMAL(18,2) COMMENT 'Sodium content per serving in milligrams as declared on the Nutrition Facts panel. Key nutrient for dietary guidance and FDA mandatory declaration.',
    `total_carbohydrate_g` DECIMAL(18,2) COMMENT 'Total carbohydrate content per serving in grams as declared on the Nutrition Facts panel, including dietary fiber and total sugars.',
    `total_fat_g` DECIMAL(18,2) COMMENT 'Total fat content per serving in grams as declared on the Nutrition Facts panel. Includes saturated fat, trans fat, polyunsaturated fat, and monounsaturated fat.',
    `upc_code` STRING COMMENT '12-digit Universal Product Code (UPC) barcode number printed on the label for retail point-of-sale scanning and supply chain identification. Assigned by GS1 and linked to the product SKU.. Valid values are `^[0-9]{12}$`',
    `usda_ams_approval_status` STRING COMMENT 'Status of the label submission and approval with the USDA Agricultural Marketing Service (AMS), required for meat, poultry, and egg products. Tracks submission through final approval or rejection.. Valid values are `not_submitted|submitted|approved|rejected|conditionally_approved`',
    `usda_grade_shield_flag` BOOLEAN COMMENT 'Indicates whether this label is authorized to display a USDA grade shield (e.g., USDA Grade A, USDA Choice). Requires grading certificate from USDA AMS grading service.',
    `version_number` STRING COMMENT 'Version identifier for this label iteration (e.g., 1.0, 2.3). Incremented whenever label content, claims, or regulatory data changes. Supports label version history and change control.. Valid values are `^[0-9]+.[0-9]+(.[0-9]+)?$`',
    CONSTRAINT pk_label PRIMARY KEY(`label_id`)
) COMMENT 'Manages all regulatory and commercial labeling content and compliance records for agricultural products. Covers COOL (Country of Origin Labeling) designations, USDA organic seal authorization, non-GMO label claims, USDA grade shield usage, allergen declarations (FDA Big 9: milk, eggs, fish, shellfish, tree nuts, peanuts, wheat, soybeans, sesame — including intentional inclusion flags, cross-contact risk levels, and allergen control measure references), nutrition facts panel data (macronutrients, micronutrients, caloric value, serving size, analysis method), net weight declarations, and label artwork file references. Captures label version, effective date, regulatory approval reference, applicable markets/jurisdictions, and HACCP allergen control plan linkage. Tracks FDA FSMA labeling and Preventive Controls allergen management compliance, USDA AMS label approval status, and supports SAP S/4HANA QM module label management.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`product`.`product_certification` (
    `product_certification_id` BIGINT COMMENT 'Unique system-generated identifier for each product certification record in the agricultural certification catalog.',
    `gmo_declaration_id` BIGINT COMMENT 'APHIS petition number or unique transformation event identifier assigned to a specific genetically modified organism event (e.g., MON810, GTS 40-3-2). Required for USDA Bioengineered (BE) food disclosure and export market approval documentation.',
    `master_id` BIGINT COMMENT 'Reference to the agricultural product or commodity in the product master catalog to which this certification applies.',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: certification is the consolidated SSOT for all third-party and regulatory certifications. When a certification record represents an NOP organic certification, it should reference the detailed organic_',
    `allowed_materials_list_ref` STRING COMMENT 'Reference identifier or document URL for the USDA NOP National List of Allowed and Prohibited Substances applicable to this organic certification scope. Ensures that only approved inputs are used in certified organic production.',
    `approved_markets` STRING COMMENT 'Comma-separated list of ISO 3-letter country codes representing jurisdictions where this GMO transformation event or certification has received regulatory approval for commercial use or import (e.g., USA, CAN, BRA, CHN, EU member states). Critical for export documentation and market access decisions.',
    `audit_cycle_months` STRING COMMENT 'Frequency of the required audit or inspection cycle expressed in months (e.g., 12 for annual, 6 for semi-annual). Determines the recurrence interval for compliance audits under the certification program.',
    `be_disclosure_required_flag` BOOLEAN COMMENT 'Indicates whether the product is subject to USDA National Bioengineered Food Disclosure Standard (NBFDS) labeling requirements. True if the product contains detectable modified genetic material from the USDA BE disclosure list.',
    `brc_grade` STRING COMMENT 'BRC Global Standard audit grade awarded at the most recent certification audit (AA, A, B, C, or D), where AA is the highest achievable grade for unannounced audits. Null if certification_type is not BRC.. Valid values are `AA|A|B|C|D`',
    `certificate_document_ref` STRING COMMENT 'File path, URL, or document management system reference to the scanned or digital copy of the official certificate document. Supports audit readiness, export documentation, and retail label claim substantiation.',
    `certificate_number` STRING COMMENT 'Externally-issued unique certificate number assigned by the certifying body (e.g., USDA NOP organic certificate number, GLOBALG.A.P. GGN, SQF certificate number). Used for audit trails, export documentation, and retail label claims.',
    `certification_scope` STRING COMMENT 'Operational scope covered by the certification as defined by the certifying body. For USDA NOP organic, scope is one of: crops, livestock, handling (processing), or wild crop. For food safety certifications, scope may reference specific product categories or processing operations.. Valid values are `crops|livestock|handling|wild_crop|multi_scope`',
    `certification_status` STRING COMMENT 'Current lifecycle state of the certification. Active indicates the certificate is valid and in force; suspended indicates a temporary hold pending investigation; revoked indicates permanent cancellation by the certifying body; expired indicates the certificate has passed its expiration date without renewal.. Valid values are `active|suspended|revoked|expired|pending|withdrawn`',
    `certification_type` STRING COMMENT 'Category of certification held by the product. Covers USDA NOP organic, USDA Bioengineered (BE) food declaration, Non-GMO Project Verified, GLOBALG.A.P., SQF, BRC, and others. [ENUM-REF-CANDIDATE: organic_nop|gmo_be_declaration|non_gmo_verified|globalg_ap|sqf|brc|ifs|fair_trade|rainforest_alliance|kosher|halal|iscc — promote to reference product]. Valid values are `organic_nop|gmo_be_declaration|non_gmo_verified|globalg_ap|sqf|brc`',
    `certifying_body_accreditation_number` STRING COMMENT 'Accreditation number assigned to the certifying body by the relevant oversight authority (e.g., USDA NOP accreditation number for organic certifying agents, GFSI accreditation reference). Validates the legitimacy of the certifying organization.',
    `certifying_body_name` STRING COMMENT 'Name of the accredited third-party organization or regulatory agency that issued the certification (e.g., Oregon Tilth, CCOF, NSF International, SGS, Bureau Veritas, Non-GMO Project, SQF Institute). Required for audit and export documentation.',
    `coa_reference` STRING COMMENT 'Reference identifier linking to the Certificate of Analysis (COA) document associated with this certification, containing laboratory test results for residues, contaminants, or identity preservation verification.',
    `cool_country_of_origin` STRING COMMENT 'ISO 3-letter country code indicating the country of origin of the certified product as required under USDA Country of Origin Labeling (COOL) regulations. Used for retail label compliance and export documentation.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the certification record was first created in the system. Supports data lineage, audit trail, and Silver layer ingestion tracking.',
    `effective_date` DATE COMMENT 'Date from which the certification is operationally effective and the product may be marketed under the certified claim. May differ from issue_date if there is a transition or grace period.',
    `expiration_date` DATE COMMENT 'Date on which the certification expires and must be renewed to maintain certified status. Critical for organic premium pricing, non-GMO market access, and retail label claims. Triggers renewal workflow when approaching.',
    `fair_trade_producer_code` STRING COMMENT 'Unique producer or cooperative code assigned by Fair Trade USA or Fairtrade International to identify the certified producer organization associated with this products fair trade certification.',
    `globalg_ap_number` STRING COMMENT '13-digit GLOBALG.A.P. Number (GGN) assigned to the certified producer or production site under the GLOBALG.A.P. certification scheme. Used for supply chain traceability and retail buyer verification via the GLOBALG.A.P. database.',
    `halal_certifying_body` STRING COMMENT 'Name of the recognized halal certifying organization (e.g., IFANCA, ISWA, HFA) that issued the halal certification for this product. Null if certification_type is not halal.',
    `ip_protocol_reference` STRING COMMENT 'Reference code or document identifier for the Identity Preservation (IP) protocol applied to maintain non-GMO or specialty crop segregation integrity throughout the supply chain. Required for Non-GMO Project Verified and identity-preserved commodity programs.',
    `issue_date` DATE COMMENT 'Date on which the certifying body formally issued the certificate. Marks the start of the certifications legal validity and is printed on the certificate document.',
    `kosher_certifying_agency` STRING COMMENT 'Name of the recognized kosher certifying agency (e.g., OU, OK, KOF-K, Star-K) that issued the kosher certification for this product. Null if certification_type is not kosher.',
    `label_claim_text` STRING COMMENT 'Approved marketing claim text authorized by this certification for use on product packaging and retail labels (e.g., USDA Organic, Non-GMO Project Verified, Certified Kosher, Fair Trade Certified). Must align with certifying body approved language.',
    `last_audit_date` DATE COMMENT 'Date of the most recent on-site inspection or audit conducted by the certifying body or accredited auditor. Used to track audit cycle compliance and readiness for renewal.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the certification record. Used for change data capture (CDC), Silver layer incremental processing, and audit trail maintenance.',
    `last_verification_date` DATE COMMENT 'Date of the most recent laboratory testing, residue verification, or document review performed to confirm ongoing compliance with certification requirements (e.g., MRL residue testing for organic, identity preservation testing for non-GMO).',
    `next_audit_date` DATE COMMENT 'Date on which the next scheduled inspection or audit by the certifying body is planned. Supports audit cycle planning and operational readiness.',
    `non_gmo_project_verified_flag` BOOLEAN COMMENT 'Indicates whether the product has received Non-GMO Project Verified status, entitling it to display the Non-GMO Project butterfly seal on retail packaging. Supports non-GMO market access and premium pricing.',
    `organic_transition_flag` BOOLEAN COMMENT 'Indicates whether the product is in the USDA NOP organic transition period (36-month land transition requirement) rather than fully certified organic. Transition products cannot be labeled or sold as certified organic.',
    `renewal_date` DATE COMMENT 'Date on which the annual or periodic renewal of the certification was last completed or is next due. Supports proactive renewal management and continuity of certified product claims.',
    `revocation_date` DATE COMMENT 'Date on which the certifying body formally revoked the certification. Populated only when certification_status is revoked. Required for regulatory reporting and product recall risk management.',
    `sqf_level` STRING COMMENT 'SQF certification level achieved: Level 1 (food safety fundamentals), Level 2 (HACCP-based food safety plan), or Level 3 (comprehensive food safety and quality management system). Null if certification_type is not SQF.. Valid values are `level_1|level_2|level_3`',
    `suspension_reason` STRING COMMENT 'Textual description of the reason for suspension of the certification by the certifying body (e.g., prohibited substance detected, recordkeeping violation, failure to allow inspection). Populated only when certification_status is suspended.',
    `transition_start_date` DATE COMMENT 'Date on which the 36-month USDA NOP organic transition period began for the associated land or product. Null if organic_transition_flag is false. Used to calculate transition completion eligibility.',
    CONSTRAINT pk_product_certification PRIMARY KEY(`product_certification_id`)
) COMMENT 'Consolidated SSOT for all third-party, regulatory, and program certifications and declarations held by agricultural products. Covers: (1) USDA NOP organic certification — certifying agent, certificate number, scope (crops/livestock/handling), effective and expiration dates, annual renewal status, allowed materials list, suspension/revocation events; (2) GMO/bioengineered food declarations — transformation event identifiers (APHIS petition numbers), approved markets by jurisdiction (US, EU, China), Non-GMO Project Verified status, identity preservation (IP) protocol reference, USDA BE labeling compliance; (3) Food safety and sustainability certifications — GLOBALG.A.P., SQF, BRC, IFS, Fair Trade, Rainforest Alliance, Kosher, Halal, ISCC. Captures certification body, certificate number, certification type, certified product scope, issue date, expiration date, audit cycle, verification/testing date, and certificate document reference. Supports organic premium pricing, non-GMO market access, export documentation, and retail label claims.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`product`.`crop_use_registration` (
    `crop_use_registration_id` BIGINT COMMENT 'Primary key for the crop_use_registration association',
    `agrochemical_product_id` BIGINT COMMENT 'Foreign key linking to the registered agrochemical product (pesticide, herbicide, fungicide, or fertilizer) in the master agrochemical catalog.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to the agricultural commodity for which this agrochemical product use is registered.',
    `approved_use_date` DATE COMMENT 'The date on which this agrochemical product was formally approved for use on this commodity in the specified jurisdiction. Required for regulatory audit trails and GLOBALG.A.P. compliance documentation.',
    `expiry_date` DATE COMMENT 'The date on which this crop-use registration expires and must be renewed with the relevant regulatory authority. Specific to the agrochemical-commodity-jurisdiction combination.',
    `jurisdiction_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code identifying the regulatory jurisdiction under which this crop-use registration is valid. The same agrochemical-commodity pair may have different approvals, rates, and PHI values across jurisdictions (e.g., USA vs. EU vs. Brazil).',
    `max_application_rate` DECIMAL(18,2) COMMENT 'The maximum allowable application rate of the agrochemical product for this specific commodity, as specified in the crop-use registration. This value is commodity-specific and may differ from the product-level max_application_rate on agrochemical_product.',
    `phi_days` STRING COMMENT 'Minimum number of days that must elapse between the last pesticide application and harvest for this commodity, as required by EPA label regulations. Ensures MRL compliance at point of harvest. Populated from agrochemical_product PHI data for the commoditys primary crop protection program. [Moved from commodity: phi_days on commodity represents a commodity-level PHI reference, but PHI is actually a function of the specific agrochemical-commodity combination, not the commodity alone. The authoritative PHI for compliance purposes belongs on the crop_use_registration association where it is tied to both the specific agrochemical product and the specific commodity.]',
    `pre_harvest_interval_days` STRING COMMENT 'The minimum number of days that must elapse between the last application of this agrochemical product and harvest of this specific commodity, as specified in the crop-use registration. Overrides the product-level PHI for this commodity context.',
    `registration_status` STRING COMMENT 'Current lifecycle status of this crop-use registration record. Tracks whether the registration is currently active, suspended by a regulatory authority, cancelled, or pending renewal. Belongs to the registration, not to either parent entity.',
    CONSTRAINT pk_crop_use_registration PRIMARY KEY(`crop_use_registration_id`)
) COMMENT 'This association product represents the regulatory Crop Use Registration (Contract) between an agrochemical_product and a commodity. It captures the EPA/USDA/international jurisdiction-specific approval of a pesticide, herbicide, fungicide, or fertilizer for application to a specific agricultural commodity. Each record links one agrochemical_product to one commodity and carries commodity-specific application rates, pre-harvest interval days, jurisdiction approvals, and approval dates that cannot be stored on either parent table. Serves as the SSOT for agrochemical compliance data at the product-commodity level, supporting FSMA, EPA label compliance, MRL enforcement, and GLOBALG.A.P. audit requirements.. Existence Justification: In agricultural regulatory practice, a single agrochemical product (e.g., a specific herbicide) is EPA/USDA registered for use on MULTIPLE commodities (corn, soybeans, wheat), and a single commodity (e.g., corn) has MULTIPLE agrochemical products registered for use on it. This crop-use registration is a formally managed regulatory record — not an analytical derivation — that carries commodity-specific application rates, pre-harvest interval days, jurisdiction approvals, and approval dates that cannot reside on either parent table. Regulatory bodies (EPA, USDA, GLOBALG.A.P.) require enterprises to actively maintain, audit, and report these registrations as standalone compliance records.';

